pragma solidity 0.6.9;
pragma experimental ABIEncoderV2;

import {
    ReentrancyGuardUpgradeSafe
} from "@openzeppelin/contracts-ethereum-package/contracts/utils/ReentrancyGuard.sol";
import { Decimal, SafeMath } from "./utils/Decimal.sol";
import { IERC20 } from "@openzeppelin/contracts-ethereum-package/contracts/token/ERC20/IERC20.sol";
import { PerpFiOwnableUpgrade } from "./utils/PerpFiOwnableUpgrade.sol";
import { DecimalERC20 } from "./utils/DecimalERC20.sol";
import { BlockContext } from "./utils/BlockContext.sol";
import { IArk } from "./interface/IArk.sol";

contract Ark is IArk, PerpFiOwnableUpgrade, BlockContext, ReentrancyGuardUpgradeSafe, DecimalERC20 {
    using Decimal for Decimal.decimal;
    using SafeMath for uint256;




    event WithdrawnForLoss(address withdrawer, uint256 amount, address token);

    struct WithdrawnToken {
        uint256 timestamp;
        Decimal.decimal cumulativeAmount;
    }

    address public insuranceFund;

    mapping(IERC20 => WithdrawnToken[]) public withdrawnTokenHistory;

    uint256[50] private __gap;




    function initialize() external initializer {
        __Ownable_init();
        __ReentrancyGuard_init();
    }


    function withdrawForLoss(Decimal.decimal memory _amount, IERC20 _quoteToken) public override {
        require(insuranceFund == _msgSender(), "only insuranceFund");

        if (_getTokenDecimals(address(_quoteToken)) < 18) {



            _amount = _amount.addD(_toDecimal(_quoteToken, 1));
        }

        require(_balanceOf(_quoteToken, address(this)).toUint() >= _amount.toUint(), "insufficient funds");


        Decimal.decimal memory cumulativeAmount;
        uint256 len = withdrawnTokenHistory[_quoteToken].length;
        if (len == 0) {
            cumulativeAmount = _amount;
        } else {
            cumulativeAmount = withdrawnTokenHistory[_quoteToken][len - 1].cumulativeAmount.addD(_amount);
        }

        withdrawnTokenHistory[_quoteToken].push(
            WithdrawnToken({ timestamp: _blockTimestamp(), cumulativeAmount: cumulativeAmount })
        );

        _transfer(_quoteToken, _msgSender(), _amount);
        emit WithdrawnForLoss(_msgSender(), _amount.toUint(), address(_quoteToken));
    }


    function claimTokens(address payable _to, IERC20 _token) external onlyOwner {
        require(_to != address(0), "to address is required");
        if (_token == IERC20(0)) {
            _to.transfer(address(this).balance);
        } else {
            _transfer(_token, _to, _balanceOf(_token, address(this)));
        }
    }

    function setInsuranceFund(address _insuranceFund) external onlyOwner {
        insuranceFund = _insuranceFund;
    }
}

pragma solidity 0.8.10;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/utils/math/SafeMath.sol";
import "@openzeppelin/contracts/access/Ownable.sol";










contract Vesting is Ownable {
    using SafeMath for uint8;
    using SafeMath for uint32;
    using SafeMath for uint256;


    address public token;
    address public operator;
    address public oracle;
    uint8 public lastScore;
    uint256 public initializedAt;
    uint256 public updatedAt;
    uint256 public totalVestingAmount;
    bool public initialized;
    bool public finalized;


    uint32 public constant EPOCH_SIZE = 60 days;

    uint256 private MAX_LOCK_AMOUNT = uint256(2**256 - 1).div(99);

    struct LockVesting {
        uint256 totalAmount;
        uint256 releasedAmount;
    }

    mapping(address => LockVesting) public locks;
    address[] beneficiaries;

    event ScoreUpdated(uint8 score, uint256 indexed epochNumber);

    modifier onlyOperator() {
        require(msg.sender == operator, "caller is not the operator");
        _;
    }

    modifier onlyOracle() {
        require(msg.sender == oracle, "caller is not the oracle");
        _;
    }

    modifier notInitialized() {
        require(!initialized, "vesting has already been initialized");
        _;
    }

    modifier isInitialized() {
        require(initialized, "vesting has not been initialized");
        _;
    }

    modifier notFinalized() {
        require(!finalized, "vesting is finalized");
        _;
    }

    constructor(
        address _token,
        address _operator,
        address _oracle
    ) {
        require(_token != address(0), "token address is required");
        require(_operator != address(0), "operator address is required");
        require(_oracle != address(0), "oracle address is required");
        token = _token;
        operator = _operator;
        oracle = _oracle;
    }




    function initialize() external onlyOperator notInitialized {
        require(totalVestingAmount != 0, "locks were not created");
        require(
            totalVestingAmount == IERC20(token).balanceOf(address(this)),
            "vesting amount and token balance are different"
        );
        initialized = true;
        initializedAt = _currentTime();
    }





    function grantVesting(address _beneficiary, uint256 _amount)
        external
        onlyOperator
        notInitialized
    {
        require(
            _amount <= MAX_LOCK_AMOUNT,
            "amount exceeds the maximum allowed value"
        );
        require(_amount != 0, "amount is required");
        require(_beneficiary != address(0), "beneficiary address is required");
        require(
            locks[_beneficiary].totalAmount == 0,
            "beneficiary already has a vesting"
        );

        locks[_beneficiary].totalAmount = _amount;
        beneficiaries.push(_beneficiary);
        totalVestingAmount = totalVestingAmount + _amount;
    }

    function setOperator(address _operator) external onlyOwner {
        require(_operator != address(0), "operator address is required");
        operator = _operator;
    }

    function setOracle(address _oracle) external onlyOwner {
        require(_oracle != address(0), "oracle address is required");
        oracle = _oracle;
    }





    function updateScore(uint8 _newScore)
        external
        onlyOracle
        isInitialized
        notFinalized
    {
        require(_newScore <= 100, "invalid score value");
        require(
            _currentTime().sub(initializedAt) > EPOCH_SIZE,
            "scoring epoch 1 still not finished"
        );

        uint256 timeFromLastEpoch = _currentTime().sub(initializedAt).mod(
            EPOCH_SIZE
        );

        require(
            timeFromLastEpoch > 0 && timeFromLastEpoch <= 1 days,
            "scoring epoch still not finished"
        );

        require(
            _currentTime().sub(updatedAt) > 1 days,
            "can not update score value twise in the same window"
        );

        lastScore = _newScore;
        updatedAt = _currentTime();

        if (_newScore != 0) {
            for (uint256 i = 0; i < beneficiaries.length; i++) {


                LockVesting memory lock = locks[beneficiaries[i]];

                uint256 remainingAmount = lock.totalAmount.sub(
                    lock.releasedAmount
                );

                uint256 releasableAmount = _newScore.mul(remainingAmount).div(
                    100
                );

                locks[beneficiaries[i]].releasedAmount = lock
                    .releasedAmount
                    .add(releasableAmount);

                require(
                    IERC20(token).transfer(beneficiaries[i], releasableAmount),
                    "token transfer fail"
                );
            }

            if (
                locks[beneficiaries[0]].releasedAmount ==
                locks[beneficiaries[0]].totalAmount
            )
                finalized = true;
        }

        emit ScoreUpdated(_newScore, _epochNumber());
    }

    function epochNumber() external view returns (uint256) {
        return _epochNumber().add(1);
    }

    function _epochNumber() internal view returns (uint256) {
        return _currentTime().sub(initializedAt).div(EPOCH_SIZE);
    }

    function _currentTime() internal view returns (uint256) {
        return block.timestamp;
    }
}

pragma solidity 0.8.4;

import {ReentrancyGuardUpgradeable} from "@openzeppelin/contracts-upgradeable/security/ReentrancyGuardUpgradeable.sol";
import {PausableUpgradeable} from "@openzeppelin/contracts-upgradeable/security/PausableUpgradeable.sol";
import {UUPSUpgradeable} from "@openzeppelin/contracts-upgradeable/proxy/utils/UUPSUpgradeable.sol";
import {IERC20} from "@openzeppelin/contracts/token/ERC20/IERC20.sol";

import {IKOAccessControlsLookup} from "../access/IKOAccessControlsLookup.sol";
import {IKODAV3} from "../core/IKODAV3.sol";


abstract contract BaseUpgradableMarketplace is ReentrancyGuardUpgradeable, PausableUpgradeable, UUPSUpgradeable {

    event AdminUpdateModulo(uint256 _modulo);
    event AdminUpdatePlatformPrimaryCommission(uint256 newAmount);
    event AdminUpdateMinBidAmount(uint256 _minBidAmount);
    event AdminUpdateAccessControls(IKOAccessControlsLookup indexed _oldAddress, IKOAccessControlsLookup indexed _newAddress);
    event AdminUpdateBidLockupPeriod(uint256 _bidLockupPeriod);
    event AdminUpdatePlatformAccount(address indexed _oldAddress, address indexed _newAddress);
    event AdminRecoverERC20(IERC20 indexed _token, address indexed _recipient, uint256 _amount);
    event AdminRecoverETH(address payable indexed _recipient, uint256 _amount);

    event BidderRefunded(uint256 indexed _id, address _bidder, uint256 _bid, address _newBidder, uint256 _newOffer);
    event BidderRefundedFailed(uint256 indexed _id, address _bidder, uint256 _bid, address _newBidder, uint256 _newOffer);


    struct KOCommissionOverride {
        bool active;
        uint256 koCommission;
    }


    modifier onlyAdmin() {
        require(accessControls.hasAdminRole(_msgSender()), "Caller not admin");
        _;
    }

    modifier onlyCreatorContractOrAdmin(uint256 _editionId) {
        require(
            koda.getCreatorOfEdition(_editionId) == _msgSender() || accessControls.hasContractOrAdminRole(_msgSender()),
            "Caller not creator or admin"
        );
        _;
    }


    IKOAccessControlsLookup public accessControls;


    IKODAV3 public koda;


    address public platformAccount;


    uint256 public modulo;


    uint256 public minBidAmount;


    uint256 public bidLockupPeriod;


    uint256 public platformPrimaryCommission;


    constructor() initializer {}

    function initialize(IKOAccessControlsLookup _accessControls, IKODAV3 _koda, address _platformAccount) public initializer {
        __ReentrancyGuard_init();
        __Pausable_init();

        accessControls = _accessControls;
        koda = _koda;
        platformAccount = _platformAccount;


        modulo = 100_00000;
        platformPrimaryCommission = 15_00000;
        minBidAmount = 0.01 ether;
        bidLockupPeriod = 6 hours;
    }

    function _authorizeUpgrade(address newImplementation) internal view override {
        require(accessControls.hasAdminRole(msg.sender), "Only admin can upgrade");
    }

    function recoverERC20(IERC20 _token, address _recipient, uint256 _amount) public onlyAdmin {

        _token.transfer(_recipient, _amount);
        emit AdminRecoverERC20(_token, _recipient, _amount);
    }

    function recoverStuckETH(address payable _recipient, uint256 _amount) public onlyAdmin {
        (bool success,) = _recipient.call{value : _amount}("");
        require(success, "Unable to send recipient ETH");
        emit AdminRecoverETH(_recipient, _amount);
    }

    function updatePlatformPrimaryCommission(uint256 _newAmount) external onlyAdmin {
        platformPrimaryCommission = _newAmount;
        emit AdminUpdatePlatformPrimaryCommission(_newAmount);
    }

    function updateAccessControls(IKOAccessControlsLookup _accessControls) public onlyAdmin {
        require(_accessControls.hasAdminRole(_msgSender()), "Sender must have admin role in new contract");
        emit AdminUpdateAccessControls(accessControls, _accessControls);
        accessControls = _accessControls;
    }

    function updateModulo(uint256 _modulo) public onlyAdmin {
        require(_modulo > 0, "Modulo point cannot be zero");
        modulo = _modulo;
        emit AdminUpdateModulo(_modulo);
    }

    function updateMinBidAmount(uint256 _minBidAmount) public onlyAdmin {
        minBidAmount = _minBidAmount;
        emit AdminUpdateMinBidAmount(_minBidAmount);
    }

    function updateBidLockupPeriod(uint256 _bidLockupPeriod) public onlyAdmin {
        bidLockupPeriod = _bidLockupPeriod;
        emit AdminUpdateBidLockupPeriod(_bidLockupPeriod);
    }

    function updatePlatformAccount(address _newPlatformAccount) public onlyAdmin {
        emit AdminUpdatePlatformAccount(platformAccount, _newPlatformAccount);
        platformAccount = _newPlatformAccount;
    }

    function pause() public onlyAdmin {
        super._pause();
    }

    function unpause() public onlyAdmin {
        super._unpause();
    }

    function _getLockupTime() internal view returns (uint256 lockupUntil) {
        lockupUntil = block.timestamp + bidLockupPeriod;
    }

    function _handleSaleFunds(address _fundsReceiver, uint256 _platformCommission) internal {
        uint256 koCommission = (msg.value / modulo) * _platformCommission;
        if (koCommission > 0) {

            (bool koCommissionSuccess,) = platformAccount.call{value : koCommission}("");
            require(koCommissionSuccess, "commission payment failed");
        }

        (bool success,) = _fundsReceiver.call{value : msg.value - koCommission}("");
        require(success, "payment failed");
    }

    function _refundBidder(uint256 _id, address _receiver, uint256 _paymentAmount, address _newBidder, uint256 _newOffer) internal {
        (bool success,) = _receiver.call{value : _paymentAmount}("");
        if (!success) {
            emit BidderRefundedFailed(_id, _receiver, _paymentAmount, _newBidder, _newOffer);
        } else {
            emit BidderRefunded(_id, _receiver, _paymentAmount, _newBidder, _newOffer);
        }
    }

}

