    mapping(address => mapping(address => uint256)) private _rewards;
    mapping(address => uint256) private _rewardsCOIN;
    mapping(address => uint256) private _distributeds;



    modifier IhaveEnoughTokens(address sc, uint256 token_amount) {
        uint256 amount = getMyTokensBalance(sc);
        require(token_amount <= amount, "-tk");
        _;
    }

    modifier IhaveEnoughCoins(uint256 coins) {
        uint256 amount = getMyCoinBalance();
        require(coins <= amount, "-coin");
        _;
    }

    modifier hasApprovedTokens(
        address sc,
        address sender,
        uint256 token_amount
    ) {
        IERC20 _token = IERC20(sc);
        require(
            _token.allowance(sender, address(this)) >= token_amount,
            "!aptk"
        ); 
        _;
    }

    modifier ProviderHasToken(address sc, uint256 amount) {
        uint256 total = calcTotalRewards(amount);
        require(total <= getTokensBalanceOf(sc, _msgSender()), "WOO:tk-");
        _;
    }

    modifier IhaveAprovedRewardTokens(address sc, uint256 amount) {
        uint256 total = calcTotalRewards(amount);
        IERC20 _token = IERC20(sc);
        require(
            _token.allowance(_msgSender(), address(this)) >= total,
            "WOO:-apt"
        );

        _;
    }

    modifier Solvency(address sc) {
        bool isSolvency;
        uint256 solvent;

        (isSolvency, solvent) = getSolvency(sc);

        require(isSolvency, "WO:sol!");
        _;
    }

    modifier SolvencyCOIN() {
        bool isSolvency;
        uint256 solvent;

        (isSolvency, solvent) = getSolvencyCOIN();

        require(isSolvency, "WO:sol!");
        _;
    }



    event RewardedCOIN(address account, uint256 reward);
    event Rewarded(address sc, address account, uint256 reward);
    event CoinReceived(uint256 coins);
    event FactorChanged(uint256 oldf, uint256 newf);
    event DistributedReseted(address sc, uint256 old);
    event DistributedCOINReseted(uint256 old);
    event RemaninderAccChanged(address old, address newr);
    event ERC20WOOPChanged(address old, address newr);
    event VestingChanged(address old, address newi);
    event StakeAddrChanged(address old, address news);
    event WithdrawFunds(address account, uint256 amount, uint256 remainder);
    event RewardWithdrawed(
        address sc,
        address account,
        uint256 amount,
        uint256 remainder
    );
    event RewardToCompound(address account, uint256 amount);

    event RewardCOINWithdrawed(
        address account,
        uint256 amount,
        uint256 remainder
    );

    event InsuficientRewardFund(address sc, address account);
    event NewLeftover(address sc, address account, uint256 leftover);
    event InsuficientRewardFundCOIN(address account);
    event NewLeftoverCOIN(address account, uint256 leftover);

    event StakeClosed(
        uint256 csc,
        uint256 stakes,
        uint256 totFunds,
        uint256 totRew
    );



    constructor(
        address remAcc,
        address woopERC20,
        address inv,
        address stake
    ) public {
        _paused = false;
        _remainder = remAcc;



        _factor = 100000000;
        _distributedCOIN = 0;
        _woopERC20 = woopERC20;
        _investable = inv;
        _inv = IInvestable(inv);
        _stakeable = stake;
        _stakes = IWStaked(stake);
    }

    function _dorewardCOIN(address account, uint256 reward) internal {
        require(account != address(0), "WO:0addr");

        _rewardsCOIN[account] = reward;
        emit RewardedCOIN(account, reward);
    }

    function rewardedCOIN(address account) public view returns (uint256) {
        return _rewardsCOIN[account];
    }

    function _rewardCOIN(address account, uint256 amount)
        internal
        returns (bool)
    {
        _dorewardCOIN(account, amount);
        return true;
    }

    function _increaseRewardsCOIN(address account, uint256 addedValue)
        internal
        returns (bool)
    {
        _dorewardCOIN(account, _rewardsCOIN[account].add(addedValue));
        return true;
    }

    function _decreaseRewardsCOIN(address account, uint256 subtractedValue)
        internal
        returns (bool)
    {
        _dorewardCOIN(
            account,
            _rewardsCOIN[account].sub(subtractedValue, "WO:-0")
        );
        return true;
    }

    function _doreward(
        address sc,
        address account,
        uint256 reward
    ) internal {
        require(sc != address(0), "WO:0addr");
        require(account != address(0), "WO:0addr");

        _rewards[sc][account] = reward;
        emit Rewarded(sc, account, reward);
    }

    function rewarded(address sc, address account)
        public
        view
        returns (uint256)
    {
        return _rewards[sc][account];
    }

    function _reward(
        address sc,
        address account,
        uint256 amount
    ) internal returns (bool) {
        _doreward(sc, account, amount);
        return true;
    }

    function _increaseRewards(
        address sc,
        address account,
        uint256 addedValue
    ) internal returns (bool) {
        _doreward(sc, account, _rewards[sc][account].add(addedValue));
        return true;
    }

    function _decreaseRewards(
        address sc,
        address account,
        uint256 subtractedValue
    ) internal returns (bool) {
        _doreward(
            sc,
            account,
            _rewards[sc][account].sub(subtractedValue, "WO:-0")
        );
        return true;
    }

    receive() external payable {

        _processRewardCOIN(msg.value);

        emit CoinReceived(msg.value);
    }

    fallback() external payable {

    }

    function getMyCoinBalance() public view returns (uint256) {
        address payable self = address(this);
        uint256 bal = self.balance;
        return bal;
    }

    function getMyTokensBalance(address sc) public view returns (uint256) {
        IERC20 _token = IERC20(sc);
        return _token.balanceOf(address(this));
    }

    function getTokensBalanceOf(address sc, address account)
        public
        view
        returns (uint256)
    {
        IERC20 _token = IERC20(sc);
        return _token.balanceOf(account);
    }

    function addErc20STK(address sc) public onlyIsInOwners returns (bool) {
        newERC20(sc);
        return true;
    }

    function removeErc20STK(address sc) public onlyIsInOwners returns (bool) {
        removeERC20(sc);
        return true;
    }

    function setFactor(uint256 newf) public onlyIsInOwners {
        require(newf <= 1000000000, ">lim");
        emit FactorChanged(_factor, newf);
        _factor = newf;
    }

    function getFactor() public view returns (uint256) {
        return _factor;
    }

    function getfractionUnit() public view returns (uint256) {
        return uint256(1000000000000000000000000000).div(_factor);
    }

    function getDistributed(address sc) public view returns (uint256) {
        return _distributeds[sc];
    }

    function resetDistributed(address sc) public onlyIsInOwners returns (bool) {
        uint256 old = _distributeds[sc];
        _distributeds[sc] = 0;
        emit DistributedReseted(sc, old);
        return true;
    }

    function getDistributedCOIN() public view returns (uint256) {
        return _distributedCOIN;
    }

    function resetDistributedCOIN() public onlyIsInOwners returns (bool) {
        uint256 old = _distributedCOIN;
        _distributedCOIN = 0;
        emit DistributedCOINReseted(old);
        return true;
    }

    function getRemaninderAcc() public view returns (address) {
        return _remainder;
    }

    function setRemaniderAcc(address newr)
        public
        onlyIsInOwners
        returns (bool)
    {
        require(newr != address(0), "!0ad");
        address old = _remainder;
        _remainder = newr;
        emit RemaninderAccChanged(old, newr);
        return true;
    }

    function getERC20WOOP() public view returns (address) {
        return _woopERC20;
    }

    function setERC20WOOP(address newr) public onlyIsInOwners returns (bool) {
        require(newr != address(0), "!0ad");
        address old = _woopERC20;
        _woopERC20 = newr;
        emit ERC20WOOPChanged(old, newr);
        return true;
    }

    function getVesting() public view returns (address) {
        return _investable;
    }

    function setVesting(address newi) public onlyIsInOwners returns (bool) {
        require(newi != address(0), "!0ad");
        address old = _investable;
        _investable = newi;
        _inv = IInvestable(newi);
        emit VestingChanged(old, newi);
        return true;
    }

    function getStakeAddr() public view returns (address) {
        return _stakeable;
    }

    function setStakeAddr(address news) public onlyIsInOwners returns (bool) {
        require(news != address(0), "!0ad");
        address old = _stakeable;
        _stakeable = news;
        _stakes = IWStaked(news);
        emit StakeAddrChanged(old, news);
        return true;
    }

    function setMyCompoundStatus(bool status)
        public
        nonReentrant
        returns (bool)
    {
        require(_stakes.StakeExist(_msgSender()), "WO:!");
        _stakes.setAutoCompound(_msgSender(), status);
        if (status == true)
            _compoundReward(_msgSender(), rewarded(_woopERC20, _msgSender()));
        return true;
    }

    function addStake(uint256 amount)
        public
        Active
        hasApprovedTokens(_woopERC20, _msgSender(), amount)
        returns (bool)
    {
        require(amount >= getfractionUnit(), "WO:-am");

        IERC20 _token = IERC20(_woopERC20);

        require(
            _token.transferFrom(_msgSender(), address(this), amount),
            "WO:-etf"
        );

        require(_addStake(_msgSender(), amount), "WO:eas");

        return true;
    }

    function _addStake(address account, uint256 amount)
        internal
        Active
        returns (bool)
    {
        if (!_stakes.StakeExist(account)) {
            _stakes.newStake(account, amount);
        } else {
            _stakes.addToStake(account, amount);
        }

        return true;
    }

    function _withdrawFunds(address account, uint256 amount)
        internal
        Active
        returns (uint256)
    {
        require(_stakes.StakeExist(account), "WO:!");
        uint256 fund;
        bool autoC;

        (fund, autoC) = _stakes.getStake(account);

        require(amount <= fund, "WO:eef");

        uint256 remainder = fund.sub(amount);

        if (remainder == 0) {
            _stakes.removeStake(account);
        } else {
            _stakes.renewStake(account, remainder);
        }

        emit WithdrawFunds(account, amount, remainder);

        return amount;
    }

    function withdrawFunds(uint256 amount)
        public
        Active
        nonReentrant
        returns (bool)
    {
        require(_stakes.StakeExist(_msgSender()), "WO:!");
        require(
            _inv.canWithdrawFunds(
                _msgSender(),
                amount,
                _stakes.balanceOf(_msgSender())
            ),
            "WO:!i"
        );

        IERC20 _token = IERC20(_woopERC20);

        require(_token.transfer(_msgSender(), amount), "WO:ewf");
        _withdrawFunds(_msgSender(), amount);

        _inv.updateFund(_msgSender(), amount);
        return true;
    }

    function _withdrawReward(
        address sc,
        address account,
        uint256 amount
    ) internal Active nonReentrant returns (uint256) {
        IERC20 _token = IERC20(sc);

        uint256 rew = rewarded(sc, account);

        require(amount <= rew, "WO:amew");

        require(amount <= getMyTokensBalance(sc), "WO:-tk");

        require(_token.transfer(account, amount));

        uint256 remainder = rew.sub(amount);



        _doreward(sc, account, remainder);


       emit RewardWithdrawed(sc, account, amount, remainder);

        return amount;
    }

    function _compoundReward(address account, uint256 amount)
        internal
        Active
        returns (uint256)
    {
        uint256 rew = rewarded(_woopERC20, account);

        require(amount <= rew, "WO: am>w");

        require(amount <= getMyTokensBalance(_woopERC20), "WO:-tk");

        uint256 remainder = rew.sub(amount);



        _doreward(_woopERC20, account, remainder);


        _stakes.addToStake(account, amount);

        emit RewardToCompound(account, amount);

        return amount;
    }

    function WithdrawReward(address sc, uint256 amount)
        public
        Active
        returns (bool)
    {
        _withdrawReward(sc, _msgSender(), amount);

        return true;
    }

    function CompoundReward(uint256 amount)
        public
        Active
        nonReentrant
        returns (bool)
    {
        _compoundReward(_msgSender(), amount);

        return true;
    }

    function _withdrawRewardCOIN(address account, uint256 amount)
        internal
        Active
        nonReentrant
        returns (uint256)
    {
        uint256 rew = rewardedCOIN(account);

        require(amount <= rew, "WO:am++");

        require(amount <= getMyCoinBalance(), "WO:tk-");

        address payable acc = address(uint160(address(account)));

        acc.transfer(amount);

        uint256 remainder = rew.sub(amount);



        _dorewardCOIN(account,remainder);

        emit RewardCOINWithdrawed(account, amount, remainder);

        return amount;
    }

    function WithdrawRewardCOIN(uint256 amount) public Active returns (bool) {
        _withdrawRewardCOIN(_msgSender(), amount);

        return true;
    }

    function getCalcRewardAmount(address account, uint256 amount)
        public
        view
        returns (uint256, uint256)
    {
        if (!_stakes.StakeExist(account)) return (0, 0);

        uint256 fund = 0;
        bool autoC;

        (fund, autoC) = _stakes.getStake(account);

        if (fund < getfractionUnit()) return (0, 0);

        uint256 factor = fund.div(getfractionUnit());

        if (factor < 1) return (0, 0);

        uint256 remainder = fund.sub(factor.mul(getfractionUnit()));

        uint256 woopsRewards = calcReward(amount, factor);

        if (woopsRewards < 1) return (0, 0);

        return (woopsRewards, remainder);
    }

    function calcReward(uint256 amount, uint256 factor)
        public
        view
        returns (uint256)
    {
        return amount.mul(factor).div(_factor);
    }

    function calcTotalRewards(uint256 amount) public view returns (uint256) {
        uint256 remainder;
        uint256 woopsRewards;
        uint256 ind = 0;
        uint256 total = 0;

        Stake memory p;

        uint256 last = _stakes.getLastIndexStakes();

        for (uint256 i = 0; i < (last + 1); i++) {
            (p.account, p.bal, p.autoCompound, p.flag) = _stakes
                .getStakeByIndex(i);

            if (p.flag == 1) {
                (woopsRewards, remainder) = getCalcRewardAmount(
                    p.account,
                    amount
                );
                if (woopsRewards > 0) {
                    total = total.add(woopsRewards);
                }
                ind++;
            }
        }

        return total;
    }

    function _processReward_1(
        IERC20 _token,
        address account,
        uint256 amount
    ) internal returns (bool) {
        require(_token.transferFrom(account, address(this), amount), "WO:etr");
        return true;
    }

    function _processReward_2(address sc, uint256 amount)
        internal
        returns (uint256)
    {
        processRewardInfo memory slot;

        Stake memory p;

        uint256 last = _stakes.getLastIndexStakes();

        for (uint256 i = 0; i < (last + 1); i++) {
            (p.account, p.bal, p.autoCompound, p.flag) = _stakes
                .getStakeByIndex(i);

            if (p.flag == 1) {
                (slot.woopsRewards, slot.remainder) = getCalcRewardAmount(
                    p.account,
                    amount
                );
                if (slot.woopsRewards > 0) {
                    if (
                        _stakes.getAutoCompoundStatus(p.account) &&
                        sc == _woopERC20
                    ) {
                        _stakes.addToStake(p.account, slot.woopsRewards);
                    } else {
                        _increaseRewards(sc, p.account, slot.woopsRewards);
                    }

                    slot.dealed = slot.dealed.add(slot.woopsRewards);
                } else {
                    emit InsuficientRewardFund(sc, p.account);
                }
            }
        } 

        _distributeds[sc] = _distributeds[sc].add(slot.dealed);

        return slot.dealed;
    }


    function processReward(address sc, uint256 amount)
        public
        nonReentrant
        Active
        hasApprovedTokens(sc, _msgSender(), amount)
        ProviderHasToken(sc, amount)
        returns (bool)
    {
        if (!ERC20Exist(sc)) {
            newERC20(sc);
        }

        processRewardInfo memory slot;

        IERC20 _token = IERC20(sc);
        _processReward_1(_token, _msgSender(), amount);

        slot.dealed = _processReward_2(sc, amount);

        uint256 leftover = amount.sub(slot.dealed);
        if (leftover > 0) {
            require(_token.transfer(_remainder, leftover), "WO:trf");
            emit NewLeftover(sc, _remainder, leftover);
        }

        return true;
    }

    function _processReward_2COIN(uint256 amount) internal returns (uint256) {
        processRewardInfo memory slot;
        Stake memory p;

        uint256 last = _stakes.getLastIndexStakes();

        for (uint256 i = 0; i < (last + 1); i++) {
            (p.account, p.bal, p.autoCompound, p.flag) = _stakes
                .getStakeByIndex(i);

            if (p.flag == 1) {
                (slot.woopsRewards, slot.remainder) = getCalcRewardAmount(
                    p.account,
                    amount
                );

                if (slot.woopsRewards > 0) {
                    _increaseRewardsCOIN(p.account, slot.woopsRewards);

                    slot.dealed = slot.dealed.add(slot.woopsRewards);
                } else {
                    emit InsuficientRewardFundCOIN(p.account);
                }
            }
        } 

        return slot.dealed;
    }

    function _processRewardCOIN(uint256 amount)
        internal
        nonReentrant
        Active
        returns (bool)
    {
        processRewardInfo memory slot;

        address payable nrem = address(uint160(_remainder));

        slot.dealed = _processReward_2COIN(amount);

        _distributedCOIN = _distributedCOIN.add(slot.dealed);

        uint256 leftover = amount.sub(slot.dealed);
        if (leftover > 0) {
            nrem.transfer(leftover);
            emit NewLeftoverCOIN(_remainder, leftover);
        }

        return true;
    }

    function closeStakes() public onlyIsInOwners nonReentrant returns (bool) {
        uint256 totRew = 0;

        uint256 toSC = _lastIndexE20s + 1;

        for (uint32 i = 0; i < (_lastIndexE20s + 1); i++) {
            E20 memory p = _E20s[i];
            if (p.flag == 1) {
                totRew = totRew.add(_withdrawAllrewards(p.sc));
            }
        }

        totRew = totRew.add(_withdrawAllrewardsCOIN());

        uint256 fund;
        bool autoC;
        uint256 funds = 0;

        Stake memory p;

        uint256 last = _stakes.getLastIndexStakes();

        for (uint256 i = 0; i < (last + 1); i++) {
            (p.account, p.bal, p.autoCompound, p.flag) = _stakes
                .getStakeByIndex(i);
            if (p.flag == 1) {
                (fund, autoC) = _stakes.getStake(p.account);
                _withdrawFunds(p.account, fund);
                funds = funds.add(fund);
            }
        }

        setPause(true);
        _stakes.removeAllStake();

        emit StakeClosed(toSC, (last + 1), funds, totRew);
        return true;
    }

    function _withdrawAllrewardsCOIN()
        internal
        SolvencyCOIN()
        nonReentrant
        returns (uint256)
    {
        uint256 total = 0;
        uint256 rew = 0;
        Stake memory p;

        uint256 last = _stakes.getLastIndexStakes();

        for (uint256 i = 0; i < (last + 1); i++) {
            (p.account, p.bal, p.autoCompound, p.flag) = _stakes
                .getStakeByIndex(i);

            if (p.flag == 1) {
                rew = rewardedCOIN(p.account);

                if (rew > 0) {
                    _withdrawRewardCOIN(p.account, rew);
                    total = total.add(rew);
                }
            }
        }

        uint256 eth_reserve = address(this).balance;

        if (eth_reserve > 0) {
            address payable ow = address(uint160(_remainder));
            ow.transfer(eth_reserve);
        }

        return total;
    }

    function _withdrawAllrewards(address sc)
        internal
        Solvency(sc)
        returns (uint256)
    {
        uint256 total = 0;
        uint256 rew = 0;

        Stake memory p;

        uint256 last = _stakes.getLastIndexStakes();

        for (uint256 i = 0; i < (last + 1); i++) {
            (p.account, p.bal, p.autoCompound, p.flag) = _stakes
                .getStakeByIndex(i);

            if (p.flag == 1) {
                rew = rewarded(sc, p.account);

                if (rew > 0) {
                    _withdrawReward(sc, p.account, rew);
                    total = total.add(rew);
                }
            }
        }

        IERC20 _token = IERC20(sc);

        uint256 token_reserve = _token.balanceOf(address(this));

        if (token_reserve > 0) {
            require(_token.transfer(_remainder, token_reserve), "WO:trf");
        }

        return total;
    }

    function getSolvencyCOIN() public view returns (bool, uint256) {
        uint256 ind = 0;
        uint256 funds = 0;
        uint256 rews = 0;
        uint256 rewsc = 0;
        uint256 autos = 0;

        (ind, funds, rews, rewsc, autos) = getStatistics(_woopERC20);

        uint256 coins = getMyCoinBalance();

        if (coins < rewsc) {
            return (false, rewsc - coins);
        } else {
            return (true, coins - rewsc);
        }
    }

    function getSolvency(address sc) public view returns (bool, uint256) {
        Stadistic memory s;

        (s.ind, s.funds, s.rews, , ) = getStatistics(sc);

        uint256 tokens = getMyTokensBalance(sc);

        uint256 tot = s.funds + s.rews;

        if (tokens < tot) {
            return (false, tot - tokens);
        } else {
            return (true, tokens - tot);
        }
    }

    function getStatistics(address sc)
        public
        view
        returns (
            uint256,
            uint256,
            uint256,
            uint256,
            uint256
        )
    {
        uint256 fund;
        bool autoC;

        Stadistic memory s;

        Stake memory p;

        uint256 last = _stakes.getLastIndexStakes();

        for (uint256 i = 0; i < (last + 1); i++) {
            (p.account, p.bal, p.autoCompound, p.flag) = _stakes
                .getStakeByIndex(i);

            if (p.flag == 1) {
                (fund, autoC) = _stakes.getStake(p.account);

                if (sc == _woopERC20) {
                    s.funds = s.funds.add(fund);
                }

                fund = rewarded(sc, p.account);

                s.rews = s.rews.add(fund);

                fund = rewardedCOIN(p.account);

                s.rewsCOIN = s.rewsCOIN.add(fund);

                if (autoC) {
                    s.autocs++;
                }
                s.ind++;
            }
        }

        return (s.ind, s.funds, s.rews, s.rewsCOIN, s.autocs);
    }
}

pragma solidity ^0.5.0;

import "./zeppelin/math/SafeMath.sol";
import "./zeppelin/token/ERC777/IERC777.sol";
import "./zeppelin/token/ERC777/IERC777Recipient.sol";
import "./zeppelin/introspection/IERC1820Registry.sol";

contract ReversibleICO is IERC777Recipient {



    using SafeMath for uint256;


    IERC1820Registry private ERC1820 = IERC1820Registry(0x1820a4B7618BdE71Dce8cdc73aAB6C95905faD24);
    bytes32 constant private TOKENS_RECIPIENT_INTERFACE_HASH = keccak256("ERC777TokensRecipient");




    bool public initialized;


    bool public frozen;
    uint256 public frozenPeriod;
    uint256 public freezeStart;




    address public deployingAddress;

    address public tokenAddress;

    address public projectAddress;

    address public whitelistingAddress;

    address public freezerAddress;

    address public rescuerAddress;




    uint256 public tokenSupply;

    uint256 public committedETH;

    uint256 public pendingETH;

    uint256 public canceledETH;

    uint256 public withdrawnETH;

    uint256 public projectWithdrawCount;

    uint256 public projectWithdrawnETH;


    uint256 public minContribution = 0.001 ether;

    mapping(uint8 => Stage) public stages;
    uint256 public stageBlockCount;
    uint8 public stageCount;


    mapping(address => Participant) public participants;

    mapping(uint256 => address) public participantsById; 

    uint256 public participantCount;



    uint256 public commitPhasePrice;

    uint256 public commitPhaseStartBlock;

    uint256 public commitPhaseEndBlock;

    uint256 public commitPhaseBlockCount;




    uint256 public buyPhaseStartBlock;

    uint256 public buyPhaseEndBlock;

    uint256 public buyPhaseBlockCount;








    uint256 internal _projectCurrentlyReservedETH;

    uint256 internal _projectUnlockedETH;

    uint256 internal _projectLastBlock;





    struct Stage {
        uint128 startBlock;
        uint128 endBlock;
        uint256 tokenPrice;
    }


    struct Participant {
        bool whitelisted;
        uint32 contributions;
        uint32 withdraws;
        uint256 reservedTokens;
        uint256 committedETH;
        uint256 pendingETH;

        uint256 _currentReservedTokens;
        uint256 _unlockedTokens;
        uint256 _lastBlock;

        mapping(uint8 => ParticipantStageDetails) stages;
    }

    struct ParticipantStageDetails {
        uint256 pendingETH;
    }


    event ApplicationEvent (
        uint8 indexed typeId,
        uint32 indexed id,
        address indexed relatedAddress,
        uint256 value
    );

    event TransferEvent (
        uint8 indexed typeId,
        address indexed relatedAddress,
        uint256 indexed value
    );

    enum ApplicationEventTypes {
        NOT_SET, 
        CONTRIBUTION_ADDED, 
        CONTRIBUTION_CANCELED, 
        CONTRIBUTION_ACCEPTED, 
        WHITELIST_APPROVED, 
        WHITELIST_REJECTED, 
        PROJECT_WITHDRAWN, 
        FROZEN_FREEZE, 
        FROZEN_UNFREEZE, 
        FROZEN_DISBALEHATCH, 
        FROZEN_ESCAPEHATCH 
    }

    enum TransferTypes {
        NOT_SET, 
        WHITELIST_REJECTED, 
        CONTRIBUTION_CANCELED, 
        CONTRIBUTION_ACCEPTED_OVERFLOW, 
        PARTICIPANT_WITHDRAW, 
        PARTICIPANT_WITHDRAW_OVERFLOW, 
        PROJECT_WITHDRAWN, 
        FROZEN_ESCAPEHATCH_TOKEN, 
        FROZEN_ESCAPEHATCH_ETH 
    }





    constructor() public {
        deployingAddress = msg.sender;
        ERC1820.setInterfaceImplementer(address(this), TOKENS_RECIPIENT_INTERFACE_HASH, address(this));
    }



    function init(
        address _tokenAddress,
        address _whitelistingAddress,
        address _projectAddress,
        uint256 _commitPhaseStartBlock,
        uint256 _commitPhaseBlockCount,
        uint256 _commitPhasePrice,
        uint8 _stageCount,
        uint256 _stageBlockCount,
        uint256 _stagePriceIncrease
    )
    public
    onlyDeployingAddress
    isNotInitialized
    {

        require(_commitPhaseStartBlock > getCurrentBlockNumber(), "Start block cannot be set in the past.");


        tokenAddress = _tokenAddress;
        whitelistingAddress = _whitelistingAddress;
        projectAddress = _projectAddress;
        freezerAddress = _projectAddress; 
        rescuerAddress = _projectAddress; 


        commitPhaseStartBlock = _commitPhaseStartBlock;
        commitPhaseBlockCount = _commitPhaseBlockCount;
        commitPhaseEndBlock = _commitPhaseStartBlock.add(_commitPhaseBlockCount).sub(1);
        commitPhasePrice = _commitPhasePrice;

        stageBlockCount = _stageBlockCount;
        stageCount = _stageCount;


        Stage storage commitPhase = stages[0];

        commitPhase.startBlock = uint128(_commitPhaseStartBlock);
        commitPhase.endBlock = uint128(commitPhaseEndBlock);
        commitPhase.tokenPrice = _commitPhasePrice;



        uint256 previousStageEndBlock = commitPhase.endBlock;


        for (uint8 i = 1; i <= _stageCount; i++) {

            Stage storage stageN = stages[i];

            stageN.startBlock = uint128(previousStageEndBlock.add(1));

            stageN.endBlock = uint128(previousStageEndBlock.add(_stageBlockCount));

            previousStageEndBlock = stageN.endBlock;

            stageN.tokenPrice = _commitPhasePrice.add(_stagePriceIncrease.mul(i));
        }



        buyPhaseStartBlock = commitPhaseEndBlock.add(1);

        buyPhaseEndBlock = previousStageEndBlock;

        buyPhaseBlockCount = buyPhaseEndBlock.sub(buyPhaseStartBlock).add(1);


        initialized = true;
    }






    function()
    external
    payable
    isInitialized
    isNotFrozen
    {
        require(msg.value < minContribution, 'To contribute, call the commit() function and send ETH along.');


        cancelPendingContributions(msg.sender, msg.value);
    }


    function tokensReceived(
        address,
        address _from,
        address,
        uint256 _amount,
        bytes calldata,
        bytes calldata
    )
    external
    isInitialized
    isNotFrozen
    {


        require(msg.sender == tokenAddress, "Invalid token contract sent tokens.");


        if (_from == projectAddress) {

            tokenSupply = tokenSupply.add(_amount);


        } else {
            withdraw(_from, _amount);
        }
    }


    function commit()
    external
    payable
    isInitialized
    isNotFrozen
    isRunning
    {

        require(msg.value >= minContribution, "Value sent is less than minimum contribution.");


        Participant storage participantStats = participants[msg.sender];
        ParticipantStageDetails storage byStage = participantStats.stages[getCurrentStage()];


        if (participantStats.contributions == 0) {

            participantsById[participantCount] = msg.sender;

            participantCount++;
        }


        participantStats.contributions++;
        participantStats.pendingETH = participantStats.pendingETH.add(msg.value);
        byStage.pendingETH = byStage.pendingETH.add(msg.value);


        pendingETH = pendingETH.add(msg.value);

        emit ApplicationEvent(
            uint8(ApplicationEventTypes.CONTRIBUTION_ADDED),
            uint32(participantStats.contributions),
            msg.sender,
            msg.value
        );


        if (participantStats.whitelisted == true) {
            acceptContributions(msg.sender);
        }
    }


    function cancel()
    external
    payable
    isInitialized
    isNotFrozen
    {
        cancelPendingContributions(msg.sender, msg.value);
    }


    function whitelist(address[] calldata _addresses, bool _approve)
    external
    onlyWhitelistingAddress
    isInitialized
    isNotFrozen
    isRunning
    {

        require(_addresses.length > 0, "No addresses given to whitelist.");

        for (uint256 i = 0; i < _addresses.length; i++) {
            address participantAddress = _addresses[i];

            Participant storage participantStats = participants[participantAddress];

            if (_approve) {
                if (!participantStats.whitelisted) {

                    participantStats.whitelisted = true;
                    emit ApplicationEvent(uint8(ApplicationEventTypes.WHITELIST_APPROVED), getCurrentStage(), participantAddress, 0);
                }


                acceptContributions(participantAddress);

            } else {
                emit ApplicationEvent(uint8(ApplicationEventTypes.WHITELIST_REJECTED), getCurrentStage(), participantAddress, 0);
                participantStats.whitelisted = false;


                cancelPendingContributions(participantAddress, 0);
            }
        }
    }


    function projectWithdraw(uint256 _ethAmount)
    external
    onlyProjectAddress
    isInitialized
    isNotFrozen
    {

        calcProjectAllocation();


        uint256 availableForWithdraw = _projectUnlockedETH.sub(projectWithdrawnETH);

        require(_ethAmount <= availableForWithdraw, "Requested amount too high, not enough ETH unlocked.");


        projectWithdrawCount++;
        projectWithdrawnETH = projectWithdrawnETH.add(_ethAmount);


        emit ApplicationEvent(
            uint8(ApplicationEventTypes.PROJECT_WITHDRAWN),
            uint32(projectWithdrawCount),
            projectAddress,
            _ethAmount
        );
        emit TransferEvent(
            uint8(TransferTypes.PROJECT_WITHDRAWN),
            projectAddress,
            _ethAmount
        );


        address(uint160(projectAddress)).transfer(_ethAmount);
    }





    function freeze()
    external
    onlyFreezerAddress
    isNotFrozen
    {
        frozen = true;
        freezeStart = getCurrentBlockNumber();


        emit ApplicationEvent(uint8(ApplicationEventTypes.FROZEN_FREEZE), uint32(getCurrentStage()), freezerAddress, getCurrentBlockNumber());
    }


    function unfreeze()
    external
    onlyFreezerAddress
    isFrozen
    {
        uint256 currentBlock = getCurrentBlockNumber();

        frozen = false;
        frozenPeriod = frozenPeriod.add(
            currentBlock.sub(freezeStart)
        );


        emit ApplicationEvent(uint8(ApplicationEventTypes.FROZEN_UNFREEZE), uint32(getCurrentStage()), freezerAddress, currentBlock);
    }


    function disableEscapeHatch()
    external
    onlyFreezerAddress
    isNotFrozen
    {
        freezerAddress = address(0);
        rescuerAddress = address(0);


        emit ApplicationEvent(uint8(ApplicationEventTypes.FROZEN_DISBALEHATCH), uint32(getCurrentStage()), freezerAddress, getCurrentBlockNumber());
    }


    function escapeHatch(address _to)
    external
    onlyRescuerAddress
    isFrozen
    {
        require(getCurrentBlockNumber() == freezeStart.add(18000), 'Let it cool.. Wait at least ~3 days (18000 blk) before moving anything.');

        uint256 tokenBalance = IERC777(tokenAddress).balanceOf(address(this));
        uint256 ethBalance = address(this).balance;



        IERC777(tokenAddress).send(_to, tokenBalance, "");


        address(uint160(_to)).transfer(ethBalance);


        emit ApplicationEvent(uint8(ApplicationEventTypes.FROZEN_ESCAPEHATCH), uint32(getCurrentStage()), _to, getCurrentBlockNumber());
        emit TransferEvent(uint8(TransferTypes.FROZEN_ESCAPEHATCH_TOKEN), _to, tokenBalance);
        emit TransferEvent(uint8(TransferTypes.FROZEN_ESCAPEHATCH_ETH), _to, ethBalance);
    }





    function getUnlockedProjectETH() public view returns (uint256) {


        uint256 newlyUnlockedEth = calcUnlockedAmount(_projectCurrentlyReservedETH, _projectLastBlock);

        return _projectUnlockedETH
        .add(newlyUnlockedEth);
    }


    function getAvailableProjectETH() public view returns (uint256) {
        return getUnlockedProjectETH()
            .sub(projectWithdrawnETH);
    }


    function getParticipantReservedTokens(address _participantAddress) public view returns (uint256) {
        Participant storage participantStats = participants[_participantAddress];

        if(participantStats._currentReservedTokens == 0) {
            return 0;
        }

        return participantStats._currentReservedTokens.sub(
            calcUnlockedAmount(participantStats._currentReservedTokens, participantStats._lastBlock)
        );
    }


    function getParticipantUnlockedTokens(address _participantAddress) public view returns (uint256) {
        Participant storage participantStats = participants[_participantAddress];

        return participantStats._unlockedTokens.add(
            calcUnlockedAmount(participantStats._currentReservedTokens, participantStats._lastBlock)
        );
    }


    function getCurrentStage() public view returns (uint8) {
        uint blockNumber;
        if (frozen) {
            blockNumber = freezeStart;
        } else {
            blockNumber = getCurrentBlockNumber().add(frozenPeriod); 
        }
    return getStageAtBlock(blockNumber);
    }


    function getCurrentPrice() public view returns (uint256) {
        uint blockNumber;
        if (frozen) {
            blockNumber = freezeStart;
        } else {
            blockNumber = getCurrentBlockNumber().add(frozenPeriod); 
        }
        return getPriceAtBlock(blockNumber);
    }


    function getPriceAtBlock(uint256 _blockNumber) public view returns (uint256) {
        return getPriceAtStage(getStageAtBlock(_blockNumber));
    }


    function getPriceAtStage(uint8 _stageId) public view returns (uint256) {
        if (_stageId <= stageCount) {
            return stages[_stageId].tokenPrice;
        }
        revert("No price data found.");
    }


    function getStageAtBlock(uint256 _blockNumber) public view returns (uint8) {

        uint256 blockNumber = _blockNumber.sub(frozenPeriod); 

        require(blockNumber >= commitPhaseStartBlock && blockNumber <= buyPhaseEndBlock, "Block outside of rICO period.");

        if (blockNumber <= commitPhaseEndBlock) {
            return 0;
        }


        uint256 distance = blockNumber - (commitPhaseEndBlock + 1);


        uint256 stageID = 1 + (distance / stageBlockCount);

        return uint8(stageID);
    }


    function committableEthAtStage(uint8 _stageId) public view returns (uint256) {
        return getEthAmountForTokensAtStage(
            tokenSupply 
        , _stageId);
    }


    function getTokenAmountForEthAtStage(uint256 _ethAmount, uint8 _stageId) public view returns (uint256) {
        return _ethAmount
        .mul(10 ** 18)
        .div(stages[_stageId].tokenPrice);
    }


    function getEthAmountForTokensAtStage(uint256 _tokenAmount, uint8 _stageId) public view returns (uint256) {
        return _tokenAmount
        .mul(stages[_stageId].tokenPrice)
        .div(10 ** 18);
    }


    function getCurrentBlockNumber() public view returns (uint256) {
        return uint256(block.number)
        .sub(frozenPeriod); 
    }


    function calcUnlockedAmount(uint256 _amount, uint256 _lastBlock) public view returns (uint256) {

        uint256 currentBlock = getCurrentBlockNumber();

        if(_amount == 0) {
            return 0;
        }


        if (currentBlock >= buyPhaseStartBlock && currentBlock < buyPhaseEndBlock) {


            uint256 lastBlock = _lastBlock;
            if(lastBlock < buyPhaseStartBlock) {
                lastBlock = buyPhaseStartBlock.sub(1); 
            }


            uint256 passedBlocks = currentBlock.sub(lastBlock);


            uint256 totalBlockCount = buyPhaseEndBlock.sub(lastBlock);

            return _amount.mul(
                passedBlocks.mul(10 ** 20)
                .div(totalBlockCount)
            ).div(10 ** 20);


        } else if (currentBlock >= buyPhaseEndBlock) {
            return _amount;
        }

        return 0;
    }





    function sanityCheckProject() internal view {

        require(
            committedETH == _projectCurrentlyReservedETH.add(_projectUnlockedETH),
            'Project Sanity check failed! Reserved + Unlock must equal committedETH'
        );






        require(
            address(this).balance == _projectUnlockedETH.add(_projectCurrentlyReservedETH).add(pendingETH).sub(projectWithdrawnETH),
            'Project sanity check failed! balance = Unlock + Reserved - Withdrawn'
        );
    }


    function sanityCheckParticipant(address _participantAddress) internal view {
        Participant storage participantStats = participants[_participantAddress];





        require(
            participantStats.reservedTokens == participantStats._currentReservedTokens.add(participantStats._unlockedTokens),
            'Participant Sanity check failed! Reser. + Unlock must equal totalReser'
        );
    }


    function calcProjectAllocation() internal {

        uint256 newlyUnlockedEth = calcUnlockedAmount(_projectCurrentlyReservedETH, _projectLastBlock);


        _projectCurrentlyReservedETH = _projectCurrentlyReservedETH.sub(newlyUnlockedEth);
        _projectUnlockedETH = _projectUnlockedETH.add(newlyUnlockedEth);
        _projectLastBlock = getCurrentBlockNumber();

        sanityCheckProject();
    }


    function calcParticipantAllocation(address _participantAddress) internal {
        Participant storage participantStats = participants[_participantAddress];


        participantStats._unlockedTokens = getParticipantUnlockedTokens(_participantAddress);
        participantStats._currentReservedTokens = getParticipantReservedTokens(_participantAddress);


        participantStats._lastBlock = getCurrentBlockNumber();


        calcProjectAllocation();
    }


    function cancelPendingContributions(address _participantAddress, uint256 _sentValue)
    internal
    isInitialized
    isNotFrozen
    {
        Participant storage participantStats = participants[_participantAddress];
        uint256 participantPendingEth = participantStats.pendingETH;


        if(participantPendingEth == 0) {

            if(_sentValue > 0) {
                address(uint160(_participantAddress)).transfer(_sentValue);
            }
            return;
        }


        for (uint8 stageId = 0; stageId <= getCurrentStage(); stageId++) {
            ParticipantStageDetails storage byStage = participantStats.stages[stageId];
            byStage.pendingETH = 0;
        }


        participantStats.pendingETH = 0;


        canceledETH = canceledETH.add(participantPendingEth);
        pendingETH = pendingETH.sub(participantPendingEth);


        emit TransferEvent(
            uint8(TransferTypes.CONTRIBUTION_CANCELED),
            _participantAddress,
            participantPendingEth
        );
        emit ApplicationEvent(
            uint8(ApplicationEventTypes.CONTRIBUTION_CANCELED),
            uint32(participantStats.contributions),
            _participantAddress,
            participantPendingEth
        );


        address(uint160(_participantAddress)).transfer(participantPendingEth.add(_sentValue));


        sanityCheckParticipant(_participantAddress);
        sanityCheckProject();
    }



    function acceptContributions(address _participantAddress)
    internal
    isInitialized
    isNotFrozen
    isRunning
    {
        Participant storage participantStats = participants[_participantAddress];


        if (participantStats.pendingETH == 0) {
            return;
        }

        uint8 currentStage = getCurrentStage();
        uint256 totalRefundedETH;
        uint256 totalNewReservedTokens;

        calcParticipantAllocation(_participantAddress);



        for (uint8 stageId = 0; stageId <= currentStage; stageId++) {
            ParticipantStageDetails storage stages = participantStats.stages[stageId];


            if (stages.pendingETH == 0) {
                continue;
            }

            uint256 maxCommittableEth = committableEthAtStage(stageId);
            uint256 newlyCommittedEth = stages.pendingETH;
            uint256 returnEth = 0;



            if (newlyCommittedEth > maxCommittableEth) {
                returnEth = newlyCommittedEth.sub(maxCommittableEth);
                newlyCommittedEth = maxCommittableEth;

                totalRefundedETH = totalRefundedETH.add(returnEth);
            }


            uint256 newTokenAmount = getTokenAmountForEthAtStage(
                newlyCommittedEth, stageId
            );

            totalNewReservedTokens = totalNewReservedTokens.add(newTokenAmount);


            participantStats._currentReservedTokens = participantStats._currentReservedTokens.add(newTokenAmount);
            participantStats.reservedTokens = participantStats.reservedTokens.add(newTokenAmount);
            participantStats.committedETH = participantStats.committedETH.add(newlyCommittedEth);
            participantStats.pendingETH = participantStats.pendingETH.sub(newlyCommittedEth).sub(returnEth);

            stages.pendingETH = stages.pendingETH.sub(newlyCommittedEth).sub(returnEth);


            tokenSupply = tokenSupply.sub(newTokenAmount);
            pendingETH = pendingETH.sub(newlyCommittedEth).sub(returnEth);
            committedETH = committedETH.add(newlyCommittedEth);
            _projectCurrentlyReservedETH = _projectCurrentlyReservedETH.add(newlyCommittedEth);


            emit ApplicationEvent(uint8(ApplicationEventTypes.CONTRIBUTION_ACCEPTED), uint32(stageId), _participantAddress, newlyCommittedEth);
        }


        if (totalRefundedETH > 0) {
            emit TransferEvent(uint8(TransferTypes.CONTRIBUTION_ACCEPTED_OVERFLOW), _participantAddress, totalRefundedETH);
            address(uint160(_participantAddress)).transfer(totalRefundedETH);
        }



        IERC777(tokenAddress).send(_participantAddress, totalNewReservedTokens, "");


        sanityCheckParticipant(_participantAddress);
        sanityCheckProject();
    }



    function withdraw(address _participantAddress, uint256 _returnedTokenAmount)
    internal
    isInitialized
    isNotFrozen
    isRunning
    {

        Participant storage participantStats = participants[_participantAddress];

        require(_returnedTokenAmount > 0, 'You can not withdraw without tokens.');
        require(participantStats._currentReservedTokens > 0 && participantStats.reservedTokens > 0, 'You can not withdraw, you have no locked tokens.');

        uint256 returnedTokenAmount = _returnedTokenAmount;
        uint256 overflowingTokenAmount;
        uint256 returnEthAmount;

        calcParticipantAllocation(_participantAddress);


        if (returnedTokenAmount > participantStats._currentReservedTokens) {
            overflowingTokenAmount = returnedTokenAmount.sub(participantStats._currentReservedTokens);
            returnedTokenAmount = participantStats._currentReservedTokens;
        }


        if(getCurrentStage() == 0) {

            returnEthAmount = getEthAmountForTokensAtStage(returnedTokenAmount, 0);


        } else {
            returnEthAmount = participantStats.committedETH.mul(
                returnedTokenAmount.mul(10 ** 20)
                .div(participantStats.reservedTokens)
            ).div(10 ** 20);
        }



        participantStats.withdraws++;
        participantStats._currentReservedTokens = participantStats._currentReservedTokens.sub(returnedTokenAmount);
        participantStats.reservedTokens = participantStats.reservedTokens.sub(returnedTokenAmount);
        participantStats.committedETH = participantStats.committedETH.sub(returnEthAmount);


        tokenSupply = tokenSupply.add(returnedTokenAmount);
        withdrawnETH = withdrawnETH.add(returnEthAmount);
        committedETH = committedETH.sub(returnEthAmount);

        _projectCurrentlyReservedETH = _projectCurrentlyReservedETH.sub(returnEthAmount);



        if (overflowingTokenAmount > 0) {

            bytes memory data;

            emit TransferEvent(uint8(TransferTypes.PARTICIPANT_WITHDRAW_OVERFLOW), _participantAddress, overflowingTokenAmount);

            IERC777(tokenAddress).send(_participantAddress, overflowingTokenAmount, data);
        }

        emit TransferEvent(uint8(TransferTypes.PARTICIPANT_WITHDRAW), _participantAddress, returnEthAmount);


        address(uint160(_participantAddress)).transfer(returnEthAmount);


        sanityCheckParticipant(_participantAddress);
        sanityCheckProject();
    }




    modifier onlyProjectAddress() {
        require(msg.sender == projectAddress, "Only the project can call this method.");
        _;
    }


    modifier onlyDeployingAddress() {
        require(msg.sender == deployingAddress, "Only the deployer can call this method.");
        _;
    }


    modifier onlyWhitelistingAddress() {
        require(msg.sender == whitelistingAddress, "Only the whitelist controller can call this method.");
        _;
    }


    modifier onlyFreezerAddress() {
        require(msg.sender == freezerAddress, "Only the freezer address can call this method.");
        _;
    }


    modifier onlyRescuerAddress() {
        require(msg.sender == rescuerAddress, "Only the rescuer address can call this method.");
        _;
    }


    modifier isInitialized() {
        require(initialized == true, "Contract must be initialized.");
        _;
    }


    modifier isNotInitialized() {
        require(initialized == false, "Contract can not be initialized.");
        _;
    }


    modifier isFrozen() {
        require(frozen == true, "rICO has to be frozen!");
        _;
    }


    modifier isNotFrozen() {
        require(frozen == false, "rICO is frozen!");
        _;
    }


    modifier isRunning() {
        uint256 blockNumber = getCurrentBlockNumber();
        require(blockNumber >= commitPhaseStartBlock && blockNumber <= buyPhaseEndBlock, "Current block is outside the rICO period.");
        _;
    }
}

pragma solidity ^0.8.0;


interface IERC20 {

    function totalSupply() external view returns (uint256);


    function balanceOf(address account) external view returns (uint256);


    function transfer(address recipient, uint256 amount)
        external
        returns (bool);


    function allowance(address owner, address spender)
        external
        view
        returns (uint256);


    function approve(address spender, uint256 amount) external returns (bool);


    function transferFrom(
        address sender,
        address recipient,
        uint256 amount
    ) external returns (bool);


    event Transfer(address indexed from, address indexed to, uint256 value);


    event Approval(
        address indexed owner,
        address indexed spender,
        uint256 value
    );
}

pragma solidity ^0.8.0;

abstract contract Context {
    function _msgSender() internal view virtual returns (address) {
        return msg.sender;
    }

    function _msgData() internal view virtual returns (bytes calldata) {
        return msg.data;
    }
}

pragma solidity 0.8.9;


abstract contract Ownable is Context {
    address private _owner;

    event OwnershipTransferred(
        address indexed previousOwner,
        address indexed newOwner
    );


    constructor() {
        _transferOwnership(_msgSender());
    }


    function owner() public view virtual returns (address) {
        return _owner;
    }


    modifier onlyOwner() {
        require(owner() == _msgSender(), "Ownable: caller is not the owner");
        _;
    }


    function renounceOwnership() public virtual onlyOwner {
        _transferOwnership(address(0));
    }


    function transferOwnership(address newOwner) public virtual onlyOwner {
        require(
            newOwner != address(0),
            "Ownable: new owner is the zero address"
        );
        _transferOwnership(newOwner);
    }


    function _transferOwnership(address newOwner) internal virtual {
        address oldOwner = _owner;
        _owner = newOwner;
        emit OwnershipTransferred(oldOwner, newOwner);
    }
}

library SafeERC20 {
    function safeTransfer(
        IERC20 token,
        address to,
        uint256 value
    ) internal {
        require(token.transfer(to, value));
    }

    function safeTransferFrom(
        IERC20 token,
        address from,
        address to,
        uint256 value
    ) internal {
        require(token.transferFrom(from, to, value));
    }
}

pragma solidity ^0.8.0;

contract TokenVesting is Ownable {
    using SafeERC20 for IERC20;

    uint256 public totalVestings;
    IERC20 public ERC20Interface;

    struct VestingDetails {
        address receiver;
        uint256 amount;
        uint256 release;
        bool expired;
    }


    constructor(address _tokenAddress) {
        require(_tokenAddress != address(0), "Zero token address");
        ERC20Interface = IERC20(_tokenAddress);
    }

    mapping(uint256 => VestingDetails) public vestingID;
    mapping(address => uint256[]) receiverIDs;


    function createVesting(
        address _receiver,
        uint256 _amount,
        uint256 _release
    ) internal onlyOwner _hasAllowance(msg.sender, _amount) returns (bool) {
        require(_receiver != address(0), "Zero receiver address");
        require(_amount > 0, "Zero amount");
        require(_release > block.timestamp, "Incorrect release time");

        totalVestings++;
        vestingID[totalVestings] = VestingDetails(
            _receiver,
            _amount,
            _release,
            false
        );
        receiverIDs[_receiver].push(totalVestings);
        ERC20Interface.safeTransferFrom(msg.sender, address(this), _amount);
        return true;
    }


    function claim(uint256 id) external returns (bool) {
        require(id > 0 && id <= totalVestings, "Id out of bounds");
        VestingDetails storage vestingDetail = vestingID[id];
        require(!vestingDetail.expired, "ID expired");
        require(
            block.timestamp >= vestingDetail.release,
            "Release time not reached"
        );
        vestingID[id].expired = true;
        ERC20Interface.safeTransfer(
            vestingDetail.receiver,
            vestingDetail.amount
        );
        return true;
    }


    function suspendLockTransferToReceiver(uint256 id)
        external
        onlyOwner
        returns (bool)
    {
        require(id > 0 && id <= totalVestings, "Id out of bounds");
        VestingDetails storage vestingDetail = vestingID[id];
        require(
            block.timestamp < vestingDetail.release,
            "Release time already reached"
        );
        require(!vestingDetail.expired, "ID expired");
        vestingID[id].expired = true;
        ERC20Interface.safeTransfer(
            vestingDetail.receiver,
            vestingDetail.amount
        );
        return true;
    }


    function createMultipleVesting(
        address[] memory _receivers,
        uint256[] memory _amounts,
        uint256[] memory _releases
    ) external returns (bool) {
        require(
            _receivers.length == _amounts.length &&
                _amounts.length == _releases.length,
            "Invalid data"
        );


        for (uint256 i = 0; i < _receivers.length; i++) {
            bool success = createVesting(
                _receivers[i],
                _amounts[i],
                _releases[i]
            );
            require(success, "Creation of vesting failed");
        }
        return true;
    }


    function getReceiverIDs(address user)
        external
        view
        returns (uint256[] memory)
    {
        return receiverIDs[user];
    }

    modifier _hasAllowance(address allower, uint256 amount) {

        uint256 ourAllowance = ERC20Interface.allowance(allower, address(this));
        require(amount <= ourAllowance, "Make sure to add enough allowance");
        _;
    }
}

pragma solidity 0.8.10;

import "oz-contracts/access/Ownable.sol";


import "oz-contracts/token/ERC20/ERC20.sol";
import "oz-contracts/token/ERC721/ERC721.sol";
import "oz-contracts/token/ERC1155/ERC1155.sol";

import "./MatchMaker.sol";
import "../utils/Errors.sol";
import "../interfaces/IRegistry.sol";

enum Reward { ERC20, ERC721, ERC1155 }

struct TournamentDetails {
  Reward  rewardType;
  uint8   matchCount;
  address rewardAddress;
  uint256 rewardId;
  uint256 rewardAmount;
}

struct Tournament {
  bool   active;
  uint16 j;
  uint16 k;
  uint48 start;
  uint48 interval;
  TournamentDetails details;
}

struct TournamentRegistration {
  bool   active;
  uint8  cost;
  uint16 playerCount;
  uint16 tournamentCount;
  uint16 maxTournamentCount;
  uint48 entryDeadline;
  TournamentDetails details;
}

struct UserRegistration {
  bool registered;
}


contract PaidTournaments is Ownable, MatchMaker {


  uint48 constant TOURNAMENT_INTERVAL = 0 seconds;
  uint256 constant TIME_CAP = 4 weeks;

  uint128 private _tournamentTypeNonce;
  uint128 private _tournamentNonce;

  event NewTournament           (uint128 tournamentType);
  event TournamentRegistered    (address user, uint128 tournamentType);
  event TournamentFull          (uint128 tournamentType, uint16 tournamentIndex);
  event TournamentCreated       (uint128 tournamentId, uint128 tournamentType);
  event TournamentFinished      (uint128 tournamentId);

  mapping(uint128 => TournamentRegistration)      public  typeToRegistry;
  mapping(uint128 => Tournament)                  public  idToTournament;
  mapping(uint128 => mapping(uint16 => address))  public  tournamentToPlayers;
  mapping(uint128 => mapping(uint16 => address))  public  typeToQueue;
  mapping(address => UserRegistration)            private userToRegistry;

  modifier onlyCore() {
    require(registry.core(msg.sender), Errors.NOT_CORE);
    _;
  }

  modifier checkStarters() {

    registry.management().checkStarters(msg.sender);
    _;
  }

  constructor(IRegistry registryAddress) MatchMaker(registryAddress) { }



  function startTournamentRegistration(
    TournamentDetails calldata details,
    uint8 cost,
    uint48 deadline, 
    uint16 maxTournamentCount
  ) external onlyCore {

    _tournamentTypeNonce++;
    TournamentRegistration storage tReg = typeToRegistry[_tournamentTypeNonce];

    require(!tReg.active, Errors.REG_STARTED);
    require(deadline > _now(), Errors.INVALID_DEADLINE);

    tReg.cost = cost;
    tReg.active = true;
    tReg.details = details;
    tReg.entryDeadline = deadline;
    tReg.maxTournamentCount = maxTournamentCount;

    Reward rewardType = details.rewardType;
    if(rewardType == Reward.ERC20) {
      require(IERC20(details.rewardAddress).transferFrom(
        msg.sender,
        address(this),
        details.rewardAmount
      ), "Token checkout failed");
    }
    else if(rewardType == Reward.ERC721) {
      IERC721(details.rewardAddress).safeTransferFrom(
        msg.sender,
        address(this),
        details.rewardId
      );
    }
    else if(rewardType == Reward.ERC1155) {
      IERC1155(details.rewardAddress).safeTransferFrom(
        msg.sender,
        address(this),
        details.rewardId,
        details.rewardAmount,
        ""
      );
    }

    emit NewTournament(_tournamentTypeNonce);
  }

  function register(uint128 tournamentType) external {

    TournamentRegistration storage tReg = typeToRegistry[tournamentType];

    require(tReg.active, Errors.REG_NOT_STARTED);
    require(tReg.tournamentCount < tReg.maxTournamentCount, Errors.TOURNAMENT_LIMIT);
    require(tReg.entryDeadline >= _now(), Errors.LATE_FOR_QUEUE);
    require(!userToRegistry[msg.sender].registered, Errors.ALREADY_REGISTERED);

    userToRegistry[msg.sender] = UserRegistration(true);
    typeToQueue[tournamentType][tReg.playerCount] = msg.sender;

    uint256 playerLimit = 2 ** tReg.details.matchCount;
    if(tReg.playerCount % playerLimit == playerLimit - 1) {
      emit TournamentFull(tournamentType, tReg.tournamentCount);
      tReg.tournamentCount++;
    }

    tReg.playerCount++;


    registry.sp1155().burn(msg.sender, 11, tReg.cost);


    registry.management().checkStarters(
      msg.sender, 
      tReg.details.matchCount, 
      tReg.entryDeadline + (tReg.details.matchCount * TOURNAMENT_INTERVAL)
    );
    registry.management().lockDefaultFive(msg.sender);
  }

  function requestTournamentRandomness() external onlyCore {
    registry.rng().requestBlockRandom(msg.sender);
  }

  function createTournament(uint128 tournamentType, uint16 tournamentIndex) external onlyCore {

    TournamentRegistration storage tReg = typeToRegistry[tournamentType];
    require(tReg.active, Errors.REG_NOT_STARTED);
    require(tReg.tournamentCount > 0, Errors.NO_TOURNAMENTS);

    uint16 playerLimit = uint16(2**tReg.details.matchCount);

    _tournamentNonce++;


    idToTournament[_tournamentNonce] = Tournament({
      active:     true,
      j:          0,
      k:          playerLimit,
      start:      tReg.entryDeadline,
      interval:   TOURNAMENT_INTERVAL,
      details:    tReg.details
    });

    for (uint16 j = 0; j < 2**playerLimit; j++) {
      tournamentToPlayers[_tournamentNonce][j] = 
        typeToQueue[tournamentType][tournamentIndex * playerLimit + j];
    }

    emit TournamentCreated(_tournamentNonce, tournamentType);
  }

  function playTournamentRound(uint128 tournamentId) external onlyCore {

    Tournament memory tournament = idToTournament[tournamentId];
    require(_now() >= tournament.start, Errors.NEXT_MATCH_NOT_READY);

    registry.rng().checkBlockRandom(msg.sender);

    uint256 tournamentRandomness = registry.rng().getBlockRandom(msg.sender);

    uint256 remainingMatches = (tournament.k - tournament.j) / 2;

    for (uint256 i = 0; i < remainingMatches; i++) {
      tournament = idToTournament[tournamentId];

      (uint8 score, , ) = matchMaker({
        enableMorale: false,
        playerOne: tournamentToPlayers[tournamentId][tournament.j],
        playerTwo: tournamentToPlayers[tournamentId][tournament.j + 1],
        randomness: tournamentRandomness
      });

      uint8 gameOffset = score >= 4 ? 1 : 0;

      registry.management().afterTournamentRound({
        userOne: tournamentToPlayers[tournamentId][tournament.j],
        userTwo: tournamentToPlayers[tournamentId][tournament.j + 1]
      });


      tournamentToPlayers[tournamentId][tournament.k] = tournamentToPlayers[tournamentId][
        tournament.j + gameOffset
      ];

      idToTournament[tournamentId].k += 1;
      idToTournament[tournamentId].j += 2;
    }




    if (idToTournament[tournamentId].k != (2**tournament.details.matchCount) * 2 - 1) {
      idToTournament[tournamentId].start += tournament.interval;
    } 
    else {
      emit TournamentFinished(tournamentId);
    }

    registry.rng().resetBlockRandom(msg.sender);
  }


  function getWinner(uint128 tournamentId) external view returns(address) {
    Tournament memory tournament = idToTournament[tournamentId];
    require(tournament.k == (2**tournament.details.matchCount) * 2 - 1, 
      Errors.TOURNAMENT_NOT_FINISHED);

    uint16 winnerIdx = uint16(2**tournament.details.matchCount) * 2 - 2;
    address first = tournamentToPlayers[tournamentId][winnerIdx];

    return first;
  }


  function finishTournament(uint128 tournamentId) external onlyCore {

    Tournament memory tournament = idToTournament[tournamentId];

    require(tournament.k == (2**tournament.details.matchCount) * 2 - 1, Errors.TOURNAMENT_NOT_FINISHED);

    uint16 winnerIdx = uint16(2**tournament.details.matchCount) * 2 - 2;
    address first = tournamentToPlayers[tournamentId][winnerIdx];

    address rewardAddress = tournament.details.rewardAddress;
    Reward rewardType = tournament.details.rewardType;



    if(rewardType == Reward.ERC20) {
      require(ERC20(rewardAddress).approve({
        spender: first, 
        amount: tournament.details.rewardAmount
      }), Errors.TOKEN_APPROVE_FAIL);
    }
    else if(rewardType == Reward.ERC721) {
      ERC721(rewardAddress).safeTransferFrom({
        from: address(this), 
        to: first, 
        tokenId: tournament.details.rewardId
      });
    }
    else if(rewardType == Reward.ERC1155) {
      ERC1155(rewardAddress).safeTransferFrom({
        from: address(this), 
        to: first, 
        id: tournament.details.rewardId, 
        amount: tournament.details.rewardAmount, 
        data: ""
      });
    }

    delete idToTournament[tournamentId].details;
    delete idToTournament[tournamentId];

    registry.management().unlockDefaultFive(first);
  }


  function onERC721Received(address,address,uint256,bytes memory) public virtual returns (bytes4) {
    return this.onERC721Received.selector;
  }


  function onERC1155Received(address,address,uint256,uint256,bytes memory) public virtual returns (bytes4) {
    return this.onERC1155Received.selector;
  }

  function _now() private view returns(uint48) {
    return uint48(block.timestamp);
  }
}

pragma solidity ^0.8.0;

import "./Interfaces/IWETH.sol";
import "./OpenZeppelin/math/Math.sol";
import "./OpenZeppelin/token/ERC20/ERC20.sol";
import "./OpenZeppelin/token/ERC721/ERC721.sol";
import "./OpenZeppelin/token/ERC721/ERC721Holder.sol";

import "./Settings.sol";

contract TokenVault is ERC20, ERC721Holder {






    address public constant weth = 0xC02aaA39b223FE8D0A0e5C4F27eAD9083C756Cc2;






    address public token;


    uint256 public id;






    uint256 public auctionEnd;


    uint256 public auctionLength;


    uint256 public basePrice;


    uint256 public reservePrice;


    uint256 public livePrice;


    address payable public winning;


    bool public auctionLive;






    address public settings;


    address public curator;


    uint256 public fee;


    uint256 public lastClaimed;


    bool public vaultClosed;


    mapping(address => uint256) public userPrices;






    event PriceUpdate(address user, uint price);


    event Start(address buyer, uint price);


    event Bid(address buyer, uint price);


    event Won(address buyer, uint price);


    event Redeem(address redeemer);


    event Cash(address owner, uint256 shares);

    constructor(address _settings, address _curator, address _token, uint256 _id, uint256 _supply, uint256 _listPrice, uint256 _fee, string memory _name, string memory _symbol) ERC20(_name, _symbol) {
        settings = _settings;
        token = _token;
        id = _id;
        basePrice = _listPrice;
        reservePrice = _listPrice;
        auctionLength = 7 days;
        curator = _curator;
        fee = _fee;
        lastClaimed = block.timestamp;

        _mint(_curator, _supply);
        _updateUserPrice(_curator, _listPrice);
    }







    function kickCurator(address _curator) external {
        require(msg.sender == Ownable(settings).owner(), "kick:not gov");

        curator = _curator;
    }







    function updateCurator(address _curator) external {
        require(msg.sender == curator, "update:not curator");

        curator = _curator;
    }



    function updateBasePrice(uint256 _price) external {
        require(msg.sender == curator, "update:not curator");

        basePrice = _price;
    }



    function updateAuctionLength(uint256 _length) external {
        require(msg.sender == curator, "update:not curator");
        require(_length >= ISettings(settings).minAuctionLength() && _length <= ISettings(settings).maxAuctionLength(), "update:invalid auction length");

        auctionLength = _length;
    }



    function updateFee(uint256 _fee) external {
        require(msg.sender == curator, "update:not curator");
        require(_fee <= ISettings(settings).maxCuratorFee(), "update:cannot increase fee this high");

        _claimFees();

        fee = _fee;
    }


    function claimFees() external {
        _claimFees();
    }


    function _claimFees() internal {

        uint256 currentAnnualFee = fee * totalSupply() / 1000; 

        uint256 feePerSecond = currentAnnualFee / 31536000;

        uint256 sinceLastClaim = block.timestamp - lastClaimed;

        uint256 curatorMint = sinceLastClaim * feePerSecond;


        address govAddress = ISettings(settings).feeReceiver();
        uint256 govFee = ISettings(settings).governanceFee();
        currentAnnualFee = govFee * totalSupply() / 1000; 
        feePerSecond = currentAnnualFee / 31536000;
        uint256 govMint = sinceLastClaim * feePerSecond;

        lastClaimed = block.timestamp;

        _mint(curator, curatorMint);
        _mint(govAddress, govMint);
    }







    function updateUserPrice(uint256 _new) external {
        require(!auctionLive, "update:auction live cannot update price");
        uint256 old = userPrices[msg.sender];
        uint256 weight = balanceOf(msg.sender);

        _updateUserPrice(msg.sender, _new);

        reservePrice = reservePrice - (weight * old / totalSupply()) + (weight * _new / totalSupply());
    }





    function _beforeTokenTransfer(address _from, address _to, uint256 _amount) internal virtual override {
        if (_from != address(0) && !auctionLive && !vaultClosed) {
            uint256 fromPrice = userPrices[_from];
            uint256 toPrice = userPrices[_to] == 0 ? reservePrice : userPrices[_to];

            _updateUserPrice(_to, toPrice);


            reservePrice = reservePrice - (_amount * fromPrice / totalSupply()) + (_amount * toPrice / totalSupply());


            if (reservePrice < basePrice) {
                uint256 basePriceMin = basePrice * ISettings(settings).minReserveFactor() / 1000;
                reservePrice = Math.max(reservePrice, basePriceMin);
            } else if (reservePrice > basePrice) {
                uint256 basePriceMax = basePrice * ISettings(settings).maxReserveFactor() / 1000;
                reservePrice = Math.min(reservePrice, basePriceMax);
            }
        }
    }




    function _updateUserPrice(address _user, uint256 _price) internal {
        userPrices[_user] = _price;

        emit PriceUpdate(_user, _price);
    }


    function start() external payable {
        require(!auctionLive && !vaultClosed, "start:no auction starts");
        require(msg.value >= reservePrice, "start:too low bid");

        auctionEnd = block.timestamp + auctionLength;
        auctionLive = true;

        livePrice = msg.value;
        winning = payable(msg.sender);

        emit Start(msg.sender, msg.value);
    }



    function bid() external payable {
        uint256 increase = ISettings(settings).minBidIncrease() + 1000;
        require(msg.value >= livePrice * increase / 1000, "bid:too low bid");
        require(block.timestamp < auctionEnd, "bid:auction ended");


        if (auctionEnd - block.timestamp <= 15 minutes) {
            auctionEnd += 15 minutes;
        }

        _sendETHOrWETH(winning, livePrice);

        livePrice = msg.value;
        winning = payable(msg.sender);

        emit Bid(msg.sender, msg.value);
    }


    function end() external {
        require(!vaultClosed, "end:vault has already closed");
        require(block.timestamp >= auctionEnd, "end:auction live");


        IERC721(token).safeTransferFrom(address(this), winning, id);

        auctionLive = false;
        vaultClosed = true;

        emit Won(winning, reservePrice);
    }


    function redeem() external {
        _burn(msg.sender, totalSupply());

        IERC721(token).safeTransferFrom(address(this), msg.sender, id);
        vaultClosed = true;

        emit Redeem(msg.sender);
    }


    function cash() external {
        require(vaultClosed, "cash:vault not closed yet");
        uint256 bal = balanceOf(msg.sender);
        require(bal > 0, "cash:no tokens to cash out");
        uint256 share = bal * address(this).balance / totalSupply();
        _burn(msg.sender, bal);

        _sendETHOrWETH(payable(msg.sender), share);

        emit Cash(msg.sender, share);
    }


    function _sendETHOrWETH(address who, uint256 amount) internal {

        (bool success, ) = who.call{ value: amount }("");

        if (!success) {
            IWETH(weth).deposit{value: amount}();
            IWETH(weth).transfer(who, IWETH(weth).balanceOf(address(this)));
        }
    }

}

pragma solidity ^0.4.19;

import '../token/ERC20/ERC20Interface.sol';
import '../math/SafeMath.sol';
import './DaicoPool.sol';


contract Voting{
    using SafeMath for uint256;

    address public votingTokenAddr;
    address public poolAddr;
    mapping (uint256 => mapping(address => uint256)) deposits;
    mapping (uint => bool) queued;

    uint256 proposalCostWei = 1 * 10**18;

    uint256 public constant VOTING_PERIOD = 14 days;

    struct Proposal {
        uint256 start_time;
        uint256 end_time;
        Subject subject;
        string reason;
        mapping (bool => uint256) votes; 
        uint256 voter_count;
        bool isFinalized;
        uint256 tapMultiplierRate;
    }

    Proposal[] public proposals;

    enum Subject {
        RaiseTap,
        Destruction
    }

    function Voting (
        address _votingTokenAddr,
        address _poolAddr
    ) public {
        require(_votingTokenAddr != address(0x0));
        votingTokenAddr = _votingTokenAddr;
        poolAddr = _poolAddr;
    }

    function addRaiseTapProposal (
        string _reason,
        uint256 _tapMultiplierRate
    ) external payable returns(uint256) {
        require(!queued[uint(Subject.RaiseTap)]);
        require(100 < _tapMultiplierRate && _tapMultiplierRate <= 200);

        uint256 newID = addProposal(Subject.RaiseTap, _reason);
        proposals[newID].tapMultiplierRate = _tapMultiplierRate;

        queued[uint(Subject.RaiseTap)] = true;
    }

    function addDestructionProposal (string _reason) external payable returns(uint256) {
        require(!queued[uint(Subject.Destruction)]);

        uint256 newID = addProposal(Subject.Destruction, _reason);

        queued[uint(Subject.Destruction)] = true;
    }

    function vote (bool agree, uint256 amount) external {
        require(ERC20Interface(votingTokenAddr).transferFrom(msg.sender, this, amount));
        uint256 pid = this.getCurrentVoting();

        require(proposals[pid].start_time >= block.timestamp);
        require(proposals[pid].end_time < block.timestamp);

        if (deposits[pid][msg.sender] == 0) {
            proposals[pid].voter_count = proposals[pid].voter_count.add(1);
        }

        deposits[pid][msg.sender] = deposits[pid][msg.sender].add(amount);
        proposals[pid].votes[agree] = proposals[pid].votes[agree].add(amount);
    }

    function finalizeVoting () external {
        uint256 pid = this.getCurrentVoting();
        require(proposals[pid].end_time <= block.timestamp);
        require(!proposals[pid].isFinalized);

        proposals[pid].isFinalized = true;

        if (isPassed(pid)) {
            if (isSubjectRaiseTap(pid)) {
                DaicoPool(poolAddr).raiseTap(proposals[pid].tapMultiplierRate);
                queued[uint(Subject.RaiseTap)] = false;
            } else if (isSubjectDestruction(pid)) {
                DaicoPool(poolAddr).selfDestruction();
                queued[uint(Subject.Destruction)] = false;
            } else {
                revert();
            }
        }
    }

    function returnToken (address account) external returns(bool) {
        uint256 amount = 0;

        for (uint256 pid = 0; pid < this.getCurrentVoting(); pid++) {
            amount = amount.add(deposits[pid][account]);
            deposits[pid][account] = 0;
        }

        if(amount <= 0){
           return false;
        }

        return ERC20Interface(votingTokenAddr).transfer(msg.sender, amount);
    }

    function returnTokenMulti (address[] accounts) external {
        for(uint256 i = 0; i < accounts.length; i++){
            this.returnToken(accounts[i]);
        }
    }

    function getCurrentVoting () public constant returns(uint256) {
        for (uint256 i = 0; i < proposals.length; i++) {
            if (!proposals[i].isFinalized) {
                return i;
            }
        }
        revert();
    }

    function isPassed (uint256 pid) public constant returns(bool) {
        require(proposals[pid].isFinalized);
        uint256 ayes = getAyes(pid);
        uint256 nays = getNays(pid);
        uint256 absent = ERC20Interface(votingTokenAddr).totalSupply().sub(ayes).sub(nays);
        return (ayes.sub(nays).add(absent.div(6)) > 0);
    }

    function isStarted (uint256 pid) public constant returns(bool) {
        if (pid > getCurrentVoting()) {
            return false;
        } else if (block.timestamp >= proposals[pid].start_time) {
            return true;
        }
        return false;
    }

    function isEnded (uint256 pid) public constant returns(bool) {
        if (pid > getCurrentVoting()) {
            return false;
        } else if (block.timestamp >= proposals[pid].end_time) {
            return true;
        }
        return false;
    }

    function getReason (uint256 pid) external constant returns(string) {
        require(pid <= getCurrentVoting());
        return proposals[pid].reason;
    }

    function isSubjectRaiseTap (uint256 pid) public constant returns(bool) {
        require(pid <= getCurrentVoting());
        return proposals[pid].subject == Subject.RaiseTap;
    }

    function isSubjectDestruction (uint256 pid) public constant returns(bool) {
        require(pid <= getCurrentVoting());
        return proposals[pid].subject == Subject.Destruction;
    }

    function getVoterCount (uint256 pid) external constant returns(uint256) {
        require(pid <= getCurrentVoting());
        return proposals[pid].voter_count;
    }

    function getAyes (uint256 pid) public constant returns(uint256) {
        require(pid <= getCurrentVoting());
        require(proposals[pid].isFinalized);
        return proposals[pid].votes[true];
    }

    function getNays (uint256 pid) public constant returns(uint256) {
        require(pid <= getCurrentVoting());
        require(proposals[pid].isFinalized);
        return proposals[pid].votes[false];
    }

    function addProposal (Subject _subject, string _reason) internal returns(uint256) {
        require(msg.value == proposalCostWei);
        poolAddr.transfer(msg.value);

        Proposal memory proposal;
        proposal.subject = _subject;
        proposal.reason = _reason;

        uint256 newID = proposals.length;
        proposals[newID] = proposal;
        return newID;
    }
}

