        if (isPassed(pid)) {
            if (isSubjectRaiseTap(pid)) {
                DaicoPool(poolAddr).raiseTap(proposals[pid].tapMultiplierRate);
                queued[uint(Subject.RaiseTap)] = false;
            } else if (isSubjectDestruction(pid)) {
                DaicoPool(poolAddr).selfDestruction();
                queued[uint(Subject.Destruction)] = false;
            } else {
                revert();
            }
        }
    }

    function returnToken (address account) external returns(bool) {
        uint256 amount = 0;

        for (uint256 pid = 0; pid < this.getCurrentVoting(); pid++) {
            amount = amount.add(deposits[pid][account]);
            deposits[pid][account] = 0;
        }

        if(amount <= 0){
           return false;
        }

        return ERC20Interface(votingTokenAddr).transfer(msg.sender, amount);
    }

    function returnTokenMulti (address[] accounts) external {
        for(uint256 i = 0; i < accounts.length; i++){
            this.returnToken(accounts[i]);
        }
    }

    function getCurrentVoting () public constant returns(uint256) {
        for (uint256 i = 0; i < proposals.length; i++) {
            if (!proposals[i].isFinalized) {
                return i;
            }
        }
        revert();
    }

    function isPassed (uint256 pid) public constant returns(bool) {
        require(proposals[pid].isFinalized);
        uint256 ayes = getAyes(pid);
        uint256 nays = getNays(pid);
        uint256 absent = ERC20Interface(votingTokenAddr).totalSupply().sub(ayes).sub(nays);
        return (ayes.sub(nays).add(absent.div(6)) > 0);
    }

    function isStarted (uint256 pid) public constant returns(bool) {
        if (pid > getCurrentVoting()) {
            return false;
        } else if (block.timestamp >= proposals[pid].start_time) {
            return true;
        }
        return false;
    }

    function isEnded (uint256 pid) public constant returns(bool) {
        if (pid > getCurrentVoting()) {
            return false;
        } else if (block.timestamp >= proposals[pid].end_time) {
            return true;
        }
        return false;
    }

    function getReason (uint256 pid) external constant returns(string) {
        require(pid <= getCurrentVoting());
        return proposals[pid].reason;
    }

    function isSubjectRaiseTap (uint256 pid) public constant returns(bool) {
        require(pid <= getCurrentVoting());
        return proposals[pid].subject == Subject.RaiseTap;
    }

    function isSubjectDestruction (uint256 pid) public constant returns(bool) {
        require(pid <= getCurrentVoting());
        return proposals[pid].subject == Subject.Destruction;
    }

    function getVoterCount (uint256 pid) external constant returns(uint256) {
        require(pid <= getCurrentVoting());
        return proposals[pid].voter_count;
    }

    function getAyes (uint256 pid) public constant returns(uint256) {
        require(pid <= getCurrentVoting());
        require(proposals[pid].isFinalized);
        return proposals[pid].votes[true];
    }

    function getNays (uint256 pid) public constant returns(uint256) {
        require(pid <= getCurrentVoting());
        require(proposals[pid].isFinalized);
        return proposals[pid].votes[false];
    }

    function addProposal (Subject _subject, string _reason) internal returns(uint256) {
        require(msg.value == proposalCostWei);
        poolAddr.transfer(msg.value);

        Proposal memory proposal;
        proposal.subject = _subject;
        proposal.reason = _reason;

        uint256 newID = proposals.length;
        proposals[newID] = proposal;
        return newID;
    }
}

pragma solidity 0.5.12;
pragma experimental ABIEncoderV2;

import "@airswap/swap/contracts/interfaces/ISwap.sol";
import "@airswap/tokens/contracts/interfaces/INRERC20.sol";
import "openzeppelin-solidity/contracts/token/ERC721/IERC721.sol";
import "openzeppelin-solidity/contracts/math/SafeMath.sol";


contract Swap is ISwap {
  using SafeMath for uint256;


  bytes constant internal DOMAIN_NAME = "SWAP";
  bytes constant internal DOMAIN_VERSION = "2";


  bytes32 private _domainSeparator;


  byte constant internal AVAILABLE = 0x00;
  byte constant internal UNAVAILABLE = 0x01;


  bytes4 constant internal ERC721_INTERFACE_ID = 0x80ac58cd;


  mapping (address => mapping (address => bool)) public senderAuthorizations;


  mapping (address => mapping (address => bool)) public signerAuthorizations;


  mapping (address => mapping (uint256 => byte)) public signerNonceStatus;


  mapping (address => uint256) public signerMinimumNonce;


  constructor() public {
    _domainSeparator = Types.hashDomain(
      DOMAIN_NAME,
      DOMAIN_VERSION,
      address(this)
    );
  }


  function swap(
    Types.Order calldata order
  ) external {

    require(order.expiry > block.timestamp,
      "ORDER_EXPIRED");


    require(signerNonceStatus[order.signer.wallet][order.nonce] == AVAILABLE,
      "ORDER_TAKEN_OR_CANCELLED");


    require(order.nonce >= signerMinimumNonce[order.signer.wallet],
      "NONCE_TOO_LOW");


    signerNonceStatus[order.signer.wallet][order.nonce] = UNAVAILABLE;


    address finalSenderWallet;

    if (order.sender.wallet == address(0)) {

      finalSenderWallet = msg.sender;

    } else {

      require(isSenderAuthorized(order.sender.wallet, msg.sender),
          "SENDER_UNAUTHORIZED");

      finalSenderWallet = order.sender.wallet;

    }


    if (order.signature.v == 0) {

      require(isSignerAuthorized(order.signer.wallet, msg.sender),
        "SIGNER_UNAUTHORIZED");

    } else {

      require(isSignerAuthorized(order.signer.wallet, order.signature.signatory),
        "SIGNER_UNAUTHORIZED");


      require(isValid(order, _domainSeparator),
        "SIGNATURE_INVALID");

    }

    transferToken(
      finalSenderWallet,
      order.signer.wallet,
      order.sender.param,
      order.sender.token,
      order.sender.kind
    );


    transferToken(
      order.signer.wallet,
      finalSenderWallet,
      order.signer.param,
      order.signer.token,
      order.signer.kind
    );


    if (order.affiliate.wallet != address(0)) {
      transferToken(
        order.signer.wallet,
        order.affiliate.wallet,
        order.affiliate.param,
        order.affiliate.token,
        order.affiliate.kind
      );
    }

    emit Swap(order.nonce, block.timestamp,
      order.signer.wallet, order.signer.param, order.signer.token,
      finalSenderWallet, order.sender.param, order.sender.token,
      order.affiliate.wallet, order.affiliate.param, order.affiliate.token
    );
  }



  function cancel(
    uint256[] calldata nonces
  ) external {
    for (uint256 i = 0; i < nonces.length; i++) {
      if (signerNonceStatus[msg.sender][nonces[i]] == AVAILABLE) {
        signerNonceStatus[msg.sender][nonces[i]] = UNAVAILABLE;
        emit Cancel(nonces[i], msg.sender);
      }
    }
  }


  function invalidate(
    uint256 minimumNonce
  ) external {
    signerMinimumNonce[msg.sender] = minimumNonce;
    emit Invalidate(minimumNonce, msg.sender);
  }


  function authorizeSender(
    address authorizedSender
  ) external {
    require(msg.sender != authorizedSender, "INVALID_AUTH_SENDER");
    senderAuthorizations[msg.sender][authorizedSender] = true;
    emit AuthorizeSender(msg.sender, authorizedSender);
  }


  function authorizeSigner(
    address authorizedSigner
  ) external {
    require(msg.sender != authorizedSigner, "INVALID_AUTH_SIGNER");
    signerAuthorizations[msg.sender][authorizedSigner] = true;
    emit AuthorizeSigner(msg.sender, authorizedSigner);
  }


  function revokeSender(
    address authorizedSender
  ) external {
    delete senderAuthorizations[msg.sender][authorizedSender];
    emit RevokeSender(msg.sender, authorizedSender);
  }


  function revokeSigner(
    address authorizedSigner
  ) external {
    delete signerAuthorizations[msg.sender][authorizedSigner];
    emit RevokeSigner(msg.sender, authorizedSigner);
  }


  function isSenderAuthorized(
    address authorizer,
    address delegate
  ) internal view returns (bool) {
    return ((authorizer == delegate) ||
      senderAuthorizations[authorizer][delegate]);
  }


  function isSignerAuthorized(
    address authorizer,
    address delegate
  ) internal view returns (bool) {
    return ((authorizer == delegate) ||
      signerAuthorizations[authorizer][delegate]);
  }


  function isValid(
    Types.Order memory order,
    bytes32 domainSeparator
  ) internal pure returns (bool) {
    if (order.signature.version == byte(0x01)) {
      return order.signature.signatory == ecrecover(
        Types.hashOrder(
          order,
          domainSeparator
        ),
        order.signature.v,
        order.signature.r,
        order.signature.s
      );
    }
    if (order.signature.version == byte(0x45)) {
      return order.signature.signatory == ecrecover(
        keccak256(
          abi.encodePacked(
            "\x19Ethereum Signed Message:\n32",
            Types.hashOrder(order, domainSeparator)
          )
        ),
        order.signature.v,
        order.signature.r,
        order.signature.s
      );
    }
    return false;
  }


  function transferToken(
      address from,
      address to,
      uint256 param,
      address token,
      bytes4 kind
  ) internal {


    require(from != to, "INVALID_SELF_TRANSFER");

    if (kind == ERC721_INTERFACE_ID) {


      IERC721(token).transferFrom(from, to, param);

    } else {
      uint256 initialBalance = INRERC20(token).balanceOf(from);


      INRERC20(token).transferFrom(from, to, param);


      require(initialBalance.sub(param) == INRERC20(token).balanceOf(from), "TRANSFER_FAILED");
    }
  }
}

pragma solidity 0.4.24;
import "../../libraries/SafeMath.sol";
import "../../libraries/Message.sol";
import "../BasicBridge.sol";
import "../../upgradeability/EternalStorage.sol";
import "../BasicHomeBridge.sol";

contract HomeBridgeNativeToErc is EternalStorage, BasicBridge, BasicHomeBridge {

    function initialize (
        address _validatorContract,
        uint256 _dailyLimit,
        uint256 _maxPerTx,
        uint256 _minPerTx,
        uint256 _homeGasPrice,
        uint256 _requiredBlockConfirmations
    ) public
      returns(bool)
    {
        require(!isInitialized());
        require(_validatorContract != address(0));
        require(_homeGasPrice > 0);
        require(_requiredBlockConfirmations > 0);
        require(_minPerTx > 0 && _maxPerTx > _minPerTx && _dailyLimit > _maxPerTx);
        addressStorage[keccak256(abi.encodePacked("validatorContract"))] = _validatorContract;
        uintStorage[keccak256(abi.encodePacked("deployedAtBlock"))] = block.number;
        uintStorage[keccak256(abi.encodePacked("dailyLimit"))] = _dailyLimit;
        uintStorage[keccak256(abi.encodePacked("maxPerTx"))] = _maxPerTx;
        uintStorage[keccak256(abi.encodePacked("minPerTx"))] = _minPerTx;
        uintStorage[keccak256(abi.encodePacked("gasPrice"))] = _homeGasPrice;
        uintStorage[keccak256(abi.encodePacked("requiredBlockConfirmations"))] = _requiredBlockConfirmations;
        setInitialize(true);
        return isInitialized();
    }

    function () public payable {
        require(msg.value > 0);
        require(msg.data.length == 0);
        require(withinLimit(msg.value));
        setTotalSpentPerDay(getCurrentDay(), totalSpentPerDay(getCurrentDay()).add(msg.value));
        emit UserRequestForSignature(msg.sender, msg.value);
    }

    function onExecuteAffirmation(address _recipient, uint256 _value) internal returns(bool) {

        _recipient.transfer(_value);
        return true;
    }
}

