pragma solidity 0.8.5;

contract Ownable {
    address public owner;
    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);
    modifier onlyOwner() {
        require(msg.sender == owner);
        _;
    }

    function transferOwnership(address newOwner) public onlyOwner {
        require(newOwner != address(0));
        emit OwnershipTransferred(owner, newOwner);
        owner = newOwner;
    }

    constructor() {
        owner = msg.sender;
    }
}

contract Pausable is Ownable {
    event Pause();
    event Unpause();

    bool public paused = false;

    modifier whenNotPaused() {
        require(!paused);
        _;
    }

    modifier whenPaused() {
        require(paused);
        _;
    }

    function pause() onlyOwner whenNotPaused public {
        paused = true;
        emit Pause();
    }

    function unpause() onlyOwner whenPaused public {
        paused = false;
        emit Unpause();
    }
}

interface IBEP20 {
    function balanceOf(address account) external view returns (uint256);
    function transfer(address recipient, uint256 amount) external returns (bool);
}
interface IDEXFactory {
    function createPair(address tokenA, address tokenB) external returns (address pair);
}
interface IDEXRouter {
    function factory() external pure returns (address);
    function addLiquidityETH(address token, uint256 amountTokenDesired, uint256 amountTokenMin, uint256 amountETHMin, address to, uint256 deadline) external payable returns (uint256 amountToken, uint256 amountETH, uint256 liquidity);
    function swapExactTokensForETHSupportingFeeOnTransferTokens(uint256 amountIn, uint256 amountOutMin, address[] calldata path, address to, uint256 deadline) external;
}

contract StandardToken is Ownable, Pausable {
    string public name;
    string public symbol;
    uint8 public decimals;
    uint256 public totalSupply;

    mapping (address => mapping(address => uint256)) public allowance;
    mapping(address => uint256) public balanceOf;

    address holdersWallet;
    address public pair;
    IDEXRouter public router;
    address public WBNB = 0xbb4CdB9CBd36B01bD1cBaEBF2De08d9173bc095c; 


    struct FeeSettings {
        uint256 liquidity;
        uint256 holders;
        uint256 burn;
        uint256 total;
        uint256 _denominator;
    }

    FeeSettings public fees = FeeSettings({
        liquidity: 0,
        holders: 3,
        burn: 2,
        total: 3,
        _denominator: 100
    });

    mapping(address => bool) public isPair;

    uint256[2] public _SWAPBACK_THRESHOLD = [1, 10000]; 
    bool public MINT_FORBIDDEN = false;
    bool inSwap;
    modifier swapping() {
        inSwap = true;
        _;
        inSwap = false;
    }

    mapping(address => bool) public tokenBlacklist;

    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);
    event Mint(address indexed from, address indexed to, uint256 value);
    event Burn(address indexed burner, uint256 value);
    event Blacklist(address indexed blackListed, bool value);
    event Pair(address indexed excluded, bool value);

    receive() external payable {}

    function transfer(address _to, uint256 _value) public whenNotPaused returns (bool) {
        require(!tokenBlacklist[msg.sender]);
        require(_to != address(0));
        _transfer(msg.sender, _to, _value);
        return true;
    }

    function transferFrom(address _from, address _to, uint256 _value) public whenNotPaused returns (bool) {
        require(!tokenBlacklist[msg.sender]);
        require(_to != address(0));
        if (allowance[_from][msg.sender] < ~uint256(0)) allowance[_from][msg.sender] -= _value;
        _transfer(_from, _to, _value);
        return true;
    }

    function _transfer(address _from, address _to, uint256 _value) internal {
        uint256 tempValue = _value;

        bool _fee = isPair[_to];
        if (_fee) {
            tempValue -= _substractBurn(_from, _value);
            tempValue -= _substractFees(_from, _value);
            _sellAndDistributeAccumulatedTKNFee();
        }
        balanceOf[_from] -= tempValue;
        balanceOf[_to] += tempValue;
        emit Transfer(_from, _to, tempValue);
    }


    function _substractBurn(address _sender, uint256 _value) internal returns (uint256 amount) {
        if (fees.burn == 0) return 0;
        amount = (_value * fees.burn) / fees._denominator;
        balanceOf[_sender] -= amount;
        totalSupply -= amount;
		emit Transfer(_sender, address(0), amount);
    }

    function _substractFees(address _sender, uint256 _value) internal returns (uint256 amount) {
        if (fees.total == 0) return 0;
        amount = (_value * fees.total) / fees._denominator;
        balanceOf[_sender] -= amount;
        balanceOf[address(this)] += amount;
		emit Transfer(_sender, address(this), amount);
    }

    function _sellAndDistributeAccumulatedTKNFee() internal swapping {
        uint256 _amount = ((totalSupply * _SWAPBACK_THRESHOLD[0]) / _SWAPBACK_THRESHOLD[1]);
        if (balanceOf[address(this)] < _amount) return;

        uint256 holdersFee = (_amount * fees.holders) / fees.total;
        _transfer(address(this), holdersWallet, holdersFee);

        uint256 halfLiquidityFee = fees.liquidity / 2;
        uint256 TKNtoLiquidity = (_amount * halfLiquidityFee) / fees.total;
        uint256 amountToSwap = _amount - holdersFee - TKNtoLiquidity;

        if (amountToSwap > 0) {
            address[] memory path = new address[](2);
            path[0] = address(this);
            path[1] = WBNB;
            router.swapExactTokensForETHSupportingFeeOnTransferTokens(amountToSwap, 0, path, address(this), block.timestamp);

        } else return;

        uint256 _gotBNB = address(this).balance;
        uint256 BNBtoLiquidity = _gotBNB;

        if (BNBtoLiquidity > 0) {
            router.addLiquidityETH{value: BNBtoLiquidity}(address(this), TKNtoLiquidity, 0, 0, owner, block.timestamp);
        }
    }

    function approve(address _spender, uint256 _value) public whenNotPaused returns (bool) {
        allowance[msg.sender][_spender] = _value;
        emit Approval(msg.sender, _spender, _value);
        return true;
    }

    function increaseApproval(address _spender, uint _value) public whenNotPaused returns (bool) {
        allowance[msg.sender][_spender] += _value;
        emit Approval(msg.sender, _spender, allowance[msg.sender][_spender]);
        return true;
    }

    function decreaseApproval(address _spender, uint _value) public whenNotPaused returns (bool) {
        if (_value >= allowance[msg.sender][_spender]) allowance[msg.sender][_spender] = 0;
        else allowance[msg.sender][_spender] -= _value;
        emit Approval(msg.sender, _spender, allowance[msg.sender][_spender]);
        return true;
    }

	function burn(uint256 _value) onlyOwner public {
		balanceOf[msg.sender] -= _value;
		totalSupply -= _value;
		emit Burn(msg.sender, _value);
		emit Transfer(msg.sender, address(0), _value);
	}
    function mint(address _who, uint256 _value) onlyOwner public {
        require(!MINT_FORBIDDEN, "mint is forbidden forever. sorry");
        balanceOf[_who] += _value;
        totalSupply += _value;
        emit Mint(address(0), _who, _value);
        emit Transfer(address(0), _who, _value);
    }
    function forbidMint() onlyOwner public {
        MINT_FORBIDDEN = true;
    }
    function setBlacklisted(address _address,  bool _isBlackListed) public onlyOwner {
        require(tokenBlacklist[_address] != _isBlackListed);
        tokenBlacklist[_address] = _isBlackListed;
        emit Blacklist(_address, _isBlackListed);
    }
    function setPair(address _address,  bool _isExcluded) public onlyOwner  {
        require(isPair[_address] != _isExcluded);
        isPair[_address] = _isExcluded;
        emit Pair(_address, _isExcluded);
    }
	function setFees(uint256 _liquidity, uint256 _holders, uint256 _burn, uint256 _denominator) onlyOwner public {
        uint256 _total = _liquidity + _holders;
        require (_total + _burn <= _denominator);
        fees = FeeSettings(_liquidity, _holders, _burn, _total, _denominator);
	}
    function setHoldersWallet(address _holdersWallet) onlyOwner public {
        holdersWallet = _holdersWallet;
	}
    function setLiquifyThreshold(uint256 _numerator, uint256 _denominator) public onlyOwner {
        _SWAPBACK_THRESHOLD = [_numerator, _denominator];
    }
    function setRouter(IDEXRouter _address) public onlyOwner {
        router = _address;
        allowance[address(this)][address(router)] = ~uint256(0);
        emit Approval(address(this), address(router), ~uint256(0));
    }
    function setPair(address _address) public onlyOwner {
        pair = _address;
    }

    constructor(address _owner) {

        name = 'Big League';
        symbol = 'BGLG';

        decimals = 18;
        totalSupply = 125 * 1e6 * 1e18;

        owner = _owner;

        balanceOf[owner] = totalSupply;
        emit Transfer(address(0), owner, totalSupply);

        holdersWallet = 0x828Ab75e87Bb5B249186c2Fe0D3bAd821a119b44; 
        router = IDEXRouter(0x10ED43C718714eb63d5aA57B78B54704E256024E); 

        allowance[address(this)][address(router)] = ~uint256(0);
        emit Approval(address(this), address(router), ~uint256(0));

        pair = IDEXFactory(router.factory()).createPair(WBNB, address(this));
        isPair[address(pair)] = true;
    }   

}

pragma solidity 0.8.4;

import "./interfaces/deposit_contract.sol";
import "./interfaces/IStakefishServicesContract.sol";
import "./libraries/Address.sol";

contract StakefishServicesContract is IStakefishServicesContract {
    using Address for address payable;

    uint256 private constant HOUR = 3600;
    uint256 private constant DAY = 24 * HOUR;
    uint256 private constant WEEK = 7 * DAY;
    uint256 private constant YEAR = 365 * DAY;
    uint256 private constant MAX_SECONDS_IN_EXIT_QUEUE = 1 * YEAR;

    uint256 private constant MAX_TIME_TO_WITHDRAW = 1 * YEAR;
    uint256 private constant COMMISSION_RATE_SCALE = 1000000;


    uint24 private _commissionRate;
    address private _operatorAddress;
    uint64 private _exitDate;
    State private _state;

    bytes32 private _operatorDataCommitment;

    mapping(address => mapping(address => uint256)) private _allowances;
    mapping(address => mapping(address => uint256)) private _allowedWithdrawals;
    mapping(address => uint256) private _deposits;
    uint256 private _totalDeposits;

    IDepositContract public constant depositContract =
        IDepositContract(0x00000000219ab540356cBB839Cbe05303d7705Fa);

    modifier onlyOperator() {
        require(
            msg.sender == _operatorAddress,
            "Caller is not the operator"
        );
        _;
    }

    modifier initializer() {
        require(
            _state == State.NotInitialized,
            "Contract is already initialized"
        );
        _state = State.PreDeposit;
        _;
    }

    function initialize(
        uint24 commissionRate,
        address operatorAddress,
        bytes32 operatorDataCommitment
    )
        external
        initializer
    {
        _commissionRate = commissionRate;
        _operatorAddress = operatorAddress;
        _operatorDataCommitment = operatorDataCommitment;
    }

    receive() payable external {
        if (_state == State.PreDeposit) {
            _handleDeposit(msg.sender);
        }
    }

    function updateExitDate(uint64 newExitDate)
        external
        override
        onlyOperator
    {
        require(
            _state == State.PostDeposit,
            "Validator is not active"
        );

        require(
            newExitDate < _exitDate,
            "Not earlier than the original value"
        );

        _exitDate = newExitDate;
    }

    function createValidator(
        bytes calldata validatorPubKey, 
        bytes calldata depositSignature, 
        bytes32 depositDataRoot,
        uint64 exitDate
    )
        external
        override
        onlyOperator
    {

        require(_state == State.PreDeposit, "Validator has been created");
        _state = State.PostDeposit;

        require(validatorPubKey.length == 48, "Invalid validator public key");
        require(depositSignature.length == 96, "Invalid deposit signature");
        require(_operatorDataCommitment == keccak256(
            abi.encodePacked(
                address(this),
                validatorPubKey,
                depositSignature,
                depositDataRoot,
                exitDate
            )
        ), "Data doesn't match commitment");

        _exitDate = exitDate;

        depositContract.deposit{value: 32 ether}(
            validatorPubKey,
            abi.encodePacked(uint96(0x010000000000000000000000), address(this)),
            depositSignature,
            depositDataRoot
        );

        emit ValidatorDeposited(validatorPubKey);
    }

    function deposit()
        external
        payable
        override
        returns (uint256 surplus)
    {
        require(
            _state == State.PreDeposit,
            "Validator already created"
        );

        return _handleDeposit(msg.sender);
    }

    function depositOnBehalfOf(address depositor)
        external
        payable
        override
        returns (uint256 surplus)
    {
        require(
            _state == State.PreDeposit,
            "Validator already created"
        );
        return _handleDeposit(depositor);
    }

    function endOperatorServices()
        external
        override
    {
        require(_state == State.PostDeposit, "Not allowed in the current state");
        require((msg.sender == _operatorAddress) ||
                (_deposits[msg.sender] > 0 && block.timestamp > _exitDate + MAX_SECONDS_IN_EXIT_QUEUE), "Not allowed at the current time");

        _state = State.Withdrawn;

        uint256 balance = address(this).balance;
        if (balance > 32 ether) {
            uint256 profit = balance - 32 ether;
            uint256 finalCommission = profit * _commissionRate / COMMISSION_RATE_SCALE;
            payable(_operatorAddress).sendValue(finalCommission);
        }

        emit ServiceEnd(block.timestamp);
    }

    string private constant WITHDRAWALS_NOT_ALLOWED =
        "Not allowed when validator is active";

    function withdrawAll()
        external
        override
        returns (uint256)
    {
        require(_state != State.PostDeposit, WITHDRAWALS_NOT_ALLOWED);
        return _executeWithdrawal(msg.sender, payable(msg.sender), _deposits[msg.sender]);
    }

    function withdraw(
        uint256 amount
    )
        external
        override
        returns (uint256)
    {
        require(_state != State.PostDeposit, WITHDRAWALS_NOT_ALLOWED);
        return _executeWithdrawal(msg.sender, payable(msg.sender), amount);
    }

    function withdrawTo(
        uint256 amount,
        address payable beneficiary
    )
        external
        override
        returns (uint256)
    {
        require(_state != State.PostDeposit, WITHDRAWALS_NOT_ALLOWED);
        return _executeWithdrawal(msg.sender, beneficiary, amount);
    }

    function approve(
        address spender,
        uint256 amount
    )
        public
        override
        returns (bool)
    {
        _approve(msg.sender, spender, amount);
        return true;
    }

    function approveWithdrawal(
        address spender,
        uint256 amount
    )
        external
        override
    {
        _allowedWithdrawals[msg.sender][spender] = amount;
        emit WithdrawalApproval(msg.sender, spender, amount);
    }

    function withdrawFrom(
        address depositor,
        address payable beneficiary,
        uint256 amount
    )
        external
        override
        returns (uint256)
    {
        require(_state != State.PostDeposit, WITHDRAWALS_NOT_ALLOWED);
        uint256 spenderAllowance = _allowedWithdrawals[depositor][msg.sender];
        uint256 newAllowance = spenderAllowance - amount;


        _allowedWithdrawals[depositor][msg.sender] = newAllowance;
        emit WithdrawalApproval(depositor, msg.sender, newAllowance);

        return _executeWithdrawal(depositor, beneficiary, amount);
    }

    function transferDeposit(
        address to,
        uint256 amount
    )
        external
        override
        returns (bool)
    {
        _transfer(msg.sender, to, amount);
        return true;
    }

    function transferDepositFrom(
        address from,
        address to,
        uint256 amount
    )
        external
        override
        returns (bool)
    {
        uint256 currentAllowance = _allowances[from][msg.sender];

        _approve(from, msg.sender, currentAllowance - amount);
        _transfer(from, to, amount);

        return true;
    }

    function withdrawalAllowance(
        address depositor,
        address spender
    )
        external
        view
        override
        returns (uint256)
    {
        return _allowedWithdrawals[depositor][spender];
    }

    function getCommissionRate()
        external
        view
        override
        returns (uint256)
    {
        return _commissionRate;
    }

    function getExitDate()
        external
        view
        override
        returns (uint256)
    {
        return _exitDate;
    }

    function getState()
        external
        view
        override
        returns(State)
    {
        return _state;
    }

    function getOperatorAddress()
        external
        view
        override
        returns (address)
    {
        return _operatorAddress;
    }

    function getDeposit(address depositor)
        external
        view
        override
        returns (uint256)
    {
        return _deposits[depositor];
    }

    function getTotalDeposits()
        external
        view
        override
        returns (uint256)
    {
        return _totalDeposits;
    }

    function getAllowance(
        address owner,
        address spender
    )
        external
        view
        override
        returns (uint256)
    {
        return _allowances[owner][spender];
    }

    function getOperatorDataCommitment()
        external
        view
        override
        returns (bytes32)
    {
        return _operatorDataCommitment;
    }

    function _executeWithdrawal(
        address depositor,
        address payable beneficiary,
        uint256 amount
    )
        internal
        returns (uint256)
    {
        require(amount > 0, "Amount shouldn't be zero");

        uint256 value = amount * address(this).balance / _totalDeposits;


        _deposits[depositor] -= amount;
        _totalDeposits -= amount;
        emit Withdrawal(depositor, beneficiary, amount, value);
        payable(beneficiary).sendValue(value);

        return value;
    }



    function _handleDeposit(address depositor)
        internal
        returns (uint256 surplus)
    {
        uint256 depositSize = msg.value;
        surplus = (address(this).balance > 32 ether) ?
            (address(this).balance - 32 ether) : 0;

        uint256 acceptedDeposit = depositSize - surplus;

        _deposits[depositor] += acceptedDeposit;
        _totalDeposits += acceptedDeposit;

        emit Deposit(depositor, acceptedDeposit);

        payable(depositor).sendValue(surplus);
    }

    function _transfer(
        address from,
        address to,
        uint256 amount
    )
        internal
    {
        require(to != address(0), "Transfer to the zero address");

        _deposits[from] -= amount;
        _deposits[to] += amount;

        emit Transfer(from, to, amount);
    }

    function _approve(
        address owner,
        address spender,
        uint256 amount
    )
        internal
    {
        require(spender != address(0), "Approve to the zero address");

        _allowances[owner][spender] = amount;
        emit Approval(owner, spender, amount);
    }
}

pragma solidity ^0.8.0;

import "./interfaces/IGovernance.sol";
import "./lib/AccessControlEnumerable.sol";
import "./lib/BytesLib.sol";


contract DistributorGovernance is AccessControlEnumerable, IGovernance {
    using BytesLib for bytes;


    bytes32 public constant GOV_ROLE = keccak256("GOV_ROLE");


    bytes32 public constant DELEGATOR_ROLE = keccak256("DELEGATOR_ROLE");


    mapping (address => address) public override rewardCollector;


    mapping (address => bool) public override blockProducer;


    bytes private _rewardSchedule;


    uint256 public constant REWARD_SCHEDULE_ENTRY_LENGTH = 32;


    modifier onlyGov() {
        require(hasRole(GOV_ROLE, msg.sender), "must be gov");
        _;
    }


    modifier onlyDelegator() {
        require(hasRole(DELEGATOR_ROLE, msg.sender), "must be delegator");
        _;
    }


    modifier onlyDelegatorOrProducer(address producer) {
        require(hasRole(DELEGATOR_ROLE, msg.sender) || msg.sender == producer, "must be producer or delegator");
        _;
    }


    constructor(
        address _admin, 
        address[] memory _blockProducers,
        address[] memory _collectors
    ) {
        require(_blockProducers.length == _collectors.length, "length mismatch");
        _setupRole(GOV_ROLE, _admin);
        _setupRole(DELEGATOR_ROLE, _admin);
        _setupRole(DEFAULT_ADMIN_ROLE, _admin);
        for(uint i; i< _blockProducers.length; i++) {
            blockProducer[_blockProducers[i]] = true;
            emit BlockProducerAdded(_blockProducers[i]);

            rewardCollector[_blockProducers[i]] = _collectors[i];
            emit BlockProducerRewardCollectorChanged(_blockProducers[i], _collectors[i]);
        }
    }


    function add(address producer) external onlyGov {
        require(blockProducer[producer] == false, "already block producer");
        blockProducer[producer] = true;
        emit BlockProducerAdded(producer);
    }


    function addBatch(address[] memory producers) external onlyGov {
        for(uint i; i< producers.length; i++) {
            require(blockProducer[producers[i]] == false, "already block producer");
            blockProducer[producers[i]] = true;
            emit BlockProducerAdded(producers[i]);
        }
    }


    function remove(address producer) external onlyGov {
        require(blockProducer[producer] == true, "not block producer");
        blockProducer[producer] = false;
        emit BlockProducerRemoved(producer);
    }


    function removeBatch(address[] memory producers) external onlyGov {
        for(uint i; i< producers.length; i++) {
            require(blockProducer[producers[i]] == true, "not block producer");
            blockProducer[producers[i]] = false;
            emit BlockProducerRemoved(producers[i]);
        }
    }


    function delegate(address producer, address collector) external onlyDelegatorOrProducer(producer) {
        rewardCollector[producer] = collector;
        emit BlockProducerRewardCollectorChanged(producer, collector);
    }


    function delegateBatch(address[] memory producers, address[] memory collectors) external onlyDelegator {
        require(producers.length == collectors.length, "length mismatch");

        for(uint i; i< producers.length; i++) {
            rewardCollector[producers[i]] = collectors[i];
            emit BlockProducerRewardCollectorChanged(producers[i], collectors[i]);
        }
    }


    function setRewardSchedule(bytes memory set) onlyGov public {
        _rewardSchedule = set;
        emit RewardScheduleChanged();
    }


    function rewardScheduleEntry(uint256 index) public override view returns (RewardScheduleEntry memory) {
        RewardScheduleEntry memory entry;
        uint256 start = index * REWARD_SCHEDULE_ENTRY_LENGTH;
        entry.startTime = _rewardSchedule.toUint64(start);
        entry.epochDuration = _rewardSchedule.toUint64(start + 8);
        entry.rewardsPerEpoch = _rewardSchedule.toUint128(start + 16);
        return entry;
    }


    function rewardScheduleEntries() public override view returns (uint256) {
        return _rewardSchedule.length / REWARD_SCHEDULE_ENTRY_LENGTH;
    }
}

pragma solidity 0.6.12;


import "openzeppelin-solidity/contracts/token/ERC20/IERC20.sol";
import "openzeppelin-solidity/contracts/token/ERC20/SafeERC20.sol";
import "openzeppelin-solidity/contracts/math/SafeMath.sol";
import "openzeppelin-solidity/contracts/math/Math.sol";
import "./SMTYToken.sol";
import "../UpgradeableOwnable.sol";


contract SmoothyMasterV1 is UpgradeableOwnable {
    using SafeMath for uint256;
    using SafeERC20 for IERC20;


    struct UserInfo {
        uint256 amount;     
        uint256 workingAmount; 
        uint256 smtyRewardDebt; 
        uint256 lockEnd;
        uint256 lockDuration;
    }


    struct PoolInfo {
        IERC20 lpToken;           
        uint256 allocPoint;       
        uint256 lastRewardTime;   
        uint256 accSMTYPerShare;  
        uint256 workingSupply;    

        mapping (address => UserInfo) userInfo;
    }


    SMTYToken public smty;
    IERC20 public veSMTY;

    address public teamAddr;
    address public communityAddr;


    PoolInfo[] public poolInfo;

    uint256 public totalAllocPoint = 0;

    uint256 public startTime;

    uint256 public constant MAX_TIME = 730 days; 
    uint256 public constant MAX_EXTRA_BOOST = 3e18; 
    uint256 public constant EMISSION_DURATION = 10 * 365 days; 
    uint256 public constant REWARD_PER_SECOND = 94000000e18 / EMISSION_DURATION;

    event Deposit(address indexed user, uint256 indexed pid, uint256 amount);
    event Withdraw(address indexed user, uint256 indexed pid, uint256 amount);
    event Claim(address indexed user, uint256 indexed pid, uint256 amount);
    event WorkingAmountUpdate(
        address indexed user,
        uint256 indexed pid,
        uint256 newWorkingAmount,
        uint256 newWorkingSupply
    );
    event LockCreate(address indexed user, uint256 indexed pid, uint256 amount, uint256 lockEnd, uint256 lockDuration);
    event LockExtend(address indexed user, uint256 indexed pid, uint256 amount, uint256 lockEnd, uint256 lockDuration);
    event LockAdd(address indexed user, uint256 indexed pid, uint256 amount, uint256 lockEnd, uint256 lockDuration);
    event LockIncreaseAmount(
        address indexed user,
        uint256 indexed pid,
        uint256 amount,
        uint256 lockEnd,
        uint256 lockDuration
    );


    constructor() public {
    }

    function initialize(
        SMTYToken _smty,
        IERC20 _veSMTY,
        address _teamAddr,
        address _communityAddr,
        uint256 _startTime
    )
        external
        onlyOwner
    {
        smty = _smty;
        veSMTY = _veSMTY;
        teamAddr = _teamAddr;
        communityAddr = _communityAddr;
        startTime = _startTime;
    }

    function poolLength() external view returns (uint256) {
        return poolInfo.length;
    }



    function add(
        uint256 _allocPoint,
        IERC20 _lpToken,
        bool _withUpdate
    )
        public
        onlyOwner
    {
        if (_withUpdate) {
            massUpdatePools();
        }
        uint256 lastRewardTime = block.timestamp > startTime ? block.timestamp : startTime;
        totalAllocPoint = totalAllocPoint.add(_allocPoint);
        poolInfo.push(PoolInfo({
            lpToken: _lpToken,
            allocPoint: _allocPoint,
            lastRewardTime: lastRewardTime,
            accSMTYPerShare: 0,
            workingSupply: 0
        }));
    }


    function set(
        uint256 _pid,
        uint256 _allocPoint,
        bool _withUpdate
    )
        public
        onlyOwner
    {
        if (_withUpdate) {
            massUpdatePools();
        }
        totalAllocPoint = totalAllocPoint.sub(poolInfo[_pid].allocPoint).add(_allocPoint);
        poolInfo[_pid].allocPoint = _allocPoint;
    }


    function getSmtyBlockReward(uint256 _from, uint256 _to) public view returns (uint256) {
        uint256 to = _to;
        if (to > startTime + EMISSION_DURATION) {
            to = startTime + EMISSION_DURATION;
        }

        uint256 from = _from;
        if (from < startTime) {
            from = startTime;
        }

        if (from > to) {
            return 0;
        }

        return (to - from + 1).mul(REWARD_PER_SECOND);
    }


    function pendingSMTY(uint256 _pid, address _user) external view returns (uint256) {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = pool.userInfo[_user];
        uint256 accSMTYPerShare = pool.accSMTYPerShare;
        uint256 workingSupply = pool.workingSupply;
        if (block.timestamp > pool.lastRewardTime && workingSupply != 0) {
            uint256 smtyReward = getSmtyBlockReward(pool.lastRewardTime + 1, block.timestamp).mul(
                pool.allocPoint).div(totalAllocPoint);
            uint256 teamReward = smtyReward.mul(20).div(94);
            uint256 communityReward = smtyReward.mul(10).div(94);
            smtyReward = smtyReward.sub(communityReward).sub(teamReward);
            accSMTYPerShare = accSMTYPerShare.add(smtyReward.mul(1e18).div(workingSupply));
        }
        return user.workingAmount.mul(accSMTYPerShare).div(1e18).sub(user.smtyRewardDebt);
    }


    function massUpdatePools() public {
        uint256 length = poolInfo.length;

        for (uint256 pid = 0; pid < length; ++pid) {
            updatePool(pid);
        }
    }


    function updatePool(uint256 _pid) public {
        _updatePool(_pid, block.timestamp);
    }

    function _updatePool(uint256 _pid, uint256 _timestamp) internal {
        PoolInfo storage pool = poolInfo[_pid];
        if (_timestamp <= pool.lastRewardTime) {
            return;
        }
        uint256 workingSupply = pool.workingSupply;
        if (workingSupply == 0) {
            pool.lastRewardTime = _timestamp;
            return;
        }
        uint256 smtyReward = getSmtyBlockReward(pool.lastRewardTime + 1, _timestamp).mul(
            pool.allocPoint).div(totalAllocPoint);
        uint256 teamReward = smtyReward.mul(20).div(94);
        uint256 communityReward = smtyReward.mul(10).div(94);
        smty.mint(teamAddr, teamReward);
        smty.mint(communityAddr, communityReward);
        smtyReward = smtyReward.sub(communityReward).sub(teamReward);
        smty.mint(address(this), smtyReward);
        pool.accSMTYPerShare = pool.accSMTYPerShare.add(smtyReward.mul(1e18).div(workingSupply));

        pool.lastRewardTime = _timestamp;
    }

    modifier claimSmty(uint256 _pid, address _account, uint256 _timestamp) {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = pool.userInfo[_account];
        _updatePool(_pid, _timestamp);
        if (user.workingAmount > 0) {
            uint256 smtyPending = user.workingAmount.mul(pool.accSMTYPerShare).div(1e18).sub(user.smtyRewardDebt);
            safeSMTYTransfer(_account, smtyPending);
            emit Claim(_account, _pid, smtyPending);
        }

        _; 

        _updateWorkingAmount(_pid, _account);
        user.smtyRewardDebt = user.workingAmount.mul(pool.accSMTYPerShare).div(1e18);
    }

    function _updateWorkingAmount(
        uint256 _pid,
        address _account
    ) internal
    {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = pool.userInfo[_account];

        uint256 lim = user.amount.mul(4) / 10;

        uint256 votingBalance = veSMTY.balanceOf(_account);
        uint256 totalBalance = veSMTY.totalSupply();

        if (totalBalance != 0) {
            uint256 lsupply = pool.lpToken.totalSupply();
            lim = lim.add(lsupply.mul(votingBalance).div(totalBalance).mul(6) / 10);
        }

        uint256 veAmount = Math.min(user.amount, lim);

        uint256 timelockBoost = user.lockDuration.mul(MAX_EXTRA_BOOST).div(MAX_TIME).add(1e18);
        uint256 newWorkingAmount = veAmount.mul(timelockBoost).div(1e18);

        pool.workingSupply = pool.workingSupply.sub(user.workingAmount).add(newWorkingAmount);
        user.workingAmount = newWorkingAmount;

        emit WorkingAmountUpdate(_account, _pid, user.workingAmount, pool.workingSupply);
    }


    function deposit(uint256 _pid, uint256 _amount) external claimSmty(_pid, msg.sender, block.timestamp) {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = pool.userInfo[msg.sender];

        require(user.lockDuration == 0, "must be unlocked");

        if (_amount > 0) {
            pool.lpToken.safeTransferFrom(address(msg.sender), address(this), _amount);
            user.amount = user.amount.add(_amount);
        }

        emit Deposit(msg.sender, _pid, _amount);
    }

    function createLock(uint256 _pid, uint256 _amount, uint256 _end) external {
        _createLock(_pid, _amount, _end, block.timestamp);
    }

    function _createLock(
        uint256 _pid,
        uint256 _amount,
        uint256 _end,
        uint256 _timestamp
    )
        internal
        claimSmty(_pid, msg.sender, _timestamp)
    {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = pool.userInfo[msg.sender];

        require(user.lockDuration == 0, "must be unlocked");
        require(_end > _timestamp, "end too short");
        require(_end <= _timestamp + MAX_TIME, "end too long");

        if (_amount != 0) {
            pool.lpToken.safeTransferFrom(address(msg.sender), address(this), _amount);
            user.amount = user.amount.add(_amount);
        }
        user.lockEnd = _end;
        user.lockDuration = _end.sub(_timestamp);

        emit LockCreate(msg.sender, _pid, user.amount, user.lockEnd, user.lockDuration);
    }

    function extendLock(uint256 _pid, uint256 _end) external claimSmty(_pid, msg.sender, block.timestamp) {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = pool.userInfo[msg.sender];

        require(user.lockDuration != 0, "must be locked");
        require(_end <= block.timestamp + MAX_TIME, "end too long");
        require(_end > user.lockEnd, "new end must be greater");
        require(user.amount != 0, "user amount must be non-zero");

        user.lockDuration = Math.min(user.lockDuration.add(_end.sub(user.lockEnd)), MAX_TIME);
        user.lockEnd = _end;

        emit LockExtend(msg.sender, _pid, user.amount, user.lockEnd, user.lockDuration);
    }

    function increaseAmount(uint256 _pid, uint256 _amount) external claimSmty(_pid, msg.sender, block.timestamp) {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = pool.userInfo[msg.sender];

        require(user.lockDuration != 0, "must be locked");
        require(user.lockEnd > block.timestamp, "must be non-expired");
        require(_amount != 0, "_amount must be nonzero");


        uint256 newAmount = user.amount.add(_amount);
        uint256 m0 = user.lockDuration.mul(user.amount);
        uint256 m1 = user.lockEnd.sub(block.timestamp).mul(_amount);
        uint256 newDuration = m0.add(m1).div(newAmount);
        user.lockDuration = newDuration;
        pool.lpToken.safeTransferFrom(address(msg.sender), address(this), _amount);
        user.amount = newAmount;

        emit LockIncreaseAmount(msg.sender, _pid, user.amount, user.lockEnd, user.lockDuration);
    }

    function withdraw(uint256 _pid) public claimSmty(_pid, msg.sender, block.timestamp) {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = pool.userInfo[msg.sender];

        require(user.lockEnd < block.timestamp, "must be expired");

        uint256 amount = user.amount;
        user.amount = 0;
        user.lockDuration = 0; 

        pool.lpToken.safeTransfer(msg.sender, amount);

        emit Withdraw(msg.sender, _pid, amount);
    }


    function claim(uint256 _pid, address _account) public claimSmty(_pid, _account, block.timestamp) {
    }


    function safeSMTYTransfer(address _to, uint256 _amount) internal {
        if (_amount > 0) {
            uint256 smtyBal = smty.balanceOf(address(this));
            if (_amount > smtyBal) {
                smty.transfer(_to, smtyBal);
            } else {
                smty.transfer(_to, _amount);
            }
        }
    }

    function getUserInfo(uint256 _pid) public view returns(uint, uint, uint, uint, uint) {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = pool.userInfo[msg.sender];

        return (user.amount, user.workingAmount, user.smtyRewardDebt, user.lockEnd, user.lockDuration);
    }
}

pragma solidity ^0.5.9;
pragma experimental ABIEncoderV2;

import "@0x/contracts-utils/contracts/src/LibBytes.sol";
import "@0x/contracts-utils/contracts/src/LibRichErrors.sol";
import "@0x/contracts-exchange-libs/contracts/src/LibOrder.sol";
import "@0x/contracts-exchange-libs/contracts/src/LibFillResults.sol";
import "@0x/contracts-exchange-libs/contracts/src/LibExchangeRichErrors.sol";
import "./interfaces/IMatchOrders.sol";
import "./MixinExchangeCore.sol";


contract MixinMatchOrders is
    MixinExchangeCore,
    IMatchOrders
{
    using LibBytes for bytes;
    using LibSafeMath for uint256;
    using LibOrder for LibOrder.Order;









    function batchMatchOrders(
        LibOrder.Order[] memory leftOrders,
        LibOrder.Order[] memory rightOrders,
        bytes[] memory leftSignatures,
        bytes[] memory rightSignatures
    )
        public
        payable
        nonReentrant
        refundFinalBalance
        returns (LibFillResults.BatchMatchedFillResults memory batchMatchedFillResults)
    {
        return _batchMatchOrders(
            leftOrders,
            rightOrders,
            leftSignatures,
            rightSignatures,
            false
        );
    }










    function batchMatchOrdersWithMaximalFill(
        LibOrder.Order[] memory leftOrders,
        LibOrder.Order[] memory rightOrders,
        bytes[] memory leftSignatures,
        bytes[] memory rightSignatures
    )
        public
        payable
        nonReentrant
        refundFinalBalance
        returns (LibFillResults.BatchMatchedFillResults memory batchMatchedFillResults)
    {
        return _batchMatchOrders(
            leftOrders,
            rightOrders,
            leftSignatures,
            rightSignatures,
            true
        );
    }










    function matchOrders(
        LibOrder.Order memory leftOrder,
        LibOrder.Order memory rightOrder,
        bytes memory leftSignature,
        bytes memory rightSignature
    )
        public
        payable
        nonReentrant
        refundFinalBalance
        returns (LibFillResults.MatchedFillResults memory matchedFillResults)
    {
        return _matchOrders(
            leftOrder,
            rightOrder,
            leftSignature,
            rightSignature,
            false
        );
    }










    function matchOrdersWithMaximalFill(
        LibOrder.Order memory leftOrder,
        LibOrder.Order memory rightOrder,
        bytes memory leftSignature,
        bytes memory rightSignature
    )
        public
        payable
        nonReentrant
        refundFinalBalance
        returns (LibFillResults.MatchedFillResults memory matchedFillResults)
    {
        return _matchOrders(
            leftOrder,
            rightOrder,
            leftSignature,
            rightSignature,
            true
        );
    }






    function _assertValidMatch(
        LibOrder.Order memory leftOrder,
        LibOrder.Order memory rightOrder,
        bytes32 leftOrderHash,
        bytes32 rightOrderHash
    )
        internal
        pure
    {








        if (leftOrder.makerAssetAmount.safeMul(rightOrder.makerAssetAmount) <
            leftOrder.takerAssetAmount.safeMul(rightOrder.takerAssetAmount)) {
            LibRichErrors.rrevert(LibExchangeRichErrors.NegativeSpreadError(
                leftOrderHash,
                rightOrderHash
            ));
        }
    }












    function _batchMatchOrders(
        LibOrder.Order[] memory leftOrders,
        LibOrder.Order[] memory rightOrders,
        bytes[] memory leftSignatures,
        bytes[] memory rightSignatures,
        bool shouldMaximallyFillOrders
    )
        internal
        returns (LibFillResults.BatchMatchedFillResults memory batchMatchedFillResults)
    {

        if (leftOrders.length == 0) {
            LibRichErrors.rrevert(LibExchangeRichErrors.BatchMatchOrdersError(
                LibExchangeRichErrors.BatchMatchOrdersErrorCodes.ZERO_LEFT_ORDERS
            ));
        }
        if (rightOrders.length == 0) {
            LibRichErrors.rrevert(LibExchangeRichErrors.BatchMatchOrdersError(
                LibExchangeRichErrors.BatchMatchOrdersErrorCodes.ZERO_RIGHT_ORDERS
            ));
        }


        if (leftOrders.length != leftSignatures.length) {
            LibRichErrors.rrevert(LibExchangeRichErrors.BatchMatchOrdersError(
                LibExchangeRichErrors.BatchMatchOrdersErrorCodes.INVALID_LENGTH_LEFT_SIGNATURES
            ));
        }
        if (rightOrders.length != rightSignatures.length) {
            LibRichErrors.rrevert(LibExchangeRichErrors.BatchMatchOrdersError(
                LibExchangeRichErrors.BatchMatchOrdersErrorCodes.INVALID_LENGTH_RIGHT_SIGNATURES
            ));
        }

        batchMatchedFillResults.left = new LibFillResults.FillResults[](leftOrders.length);
        batchMatchedFillResults.right = new LibFillResults.FillResults[](rightOrders.length);


        uint256 leftIdx = 0;
        uint256 rightIdx = 0;


        LibOrder.Order memory leftOrder = leftOrders[0];
        LibOrder.Order memory rightOrder = rightOrders[0];
        (, uint256 leftOrderTakerAssetFilledAmount) = _getOrderHashAndFilledAmount(leftOrder);
        (, uint256 rightOrderTakerAssetFilledAmount) = _getOrderHashAndFilledAmount(rightOrder);
        LibFillResults.FillResults memory leftFillResults;
        LibFillResults.FillResults memory rightFillResults;



        for (;;) {

            LibFillResults.MatchedFillResults memory matchResults = _matchOrders(
                leftOrder,
                rightOrder,
                leftSignatures[leftIdx],
                rightSignatures[rightIdx],
                shouldMaximallyFillOrders
            );


            leftOrderTakerAssetFilledAmount = leftOrderTakerAssetFilledAmount.safeAdd(matchResults.left.takerAssetFilledAmount);
            rightOrderTakerAssetFilledAmount = rightOrderTakerAssetFilledAmount.safeAdd(matchResults.right.takerAssetFilledAmount);


            leftFillResults = LibFillResults.addFillResults(
                leftFillResults,
                matchResults.left
            );
            rightFillResults = LibFillResults.addFillResults(
                rightFillResults,
                matchResults.right
            );



            batchMatchedFillResults.profitInLeftMakerAsset = batchMatchedFillResults.profitInLeftMakerAsset.safeAdd(
                matchResults.profitInLeftMakerAsset
            );
            batchMatchedFillResults.profitInRightMakerAsset = batchMatchedFillResults.profitInRightMakerAsset.safeAdd(
                matchResults.profitInRightMakerAsset
            );



            if (leftOrderTakerAssetFilledAmount >= leftOrder.takerAssetAmount) {

                batchMatchedFillResults.left[leftIdx++] = leftFillResults;

                leftFillResults = LibFillResults.FillResults(0, 0, 0, 0, 0);



                if (leftIdx == leftOrders.length) {

                    batchMatchedFillResults.right[rightIdx] = rightFillResults;
                    break;
                } else {
                    leftOrder = leftOrders[leftIdx];
                    (, leftOrderTakerAssetFilledAmount) = _getOrderHashAndFilledAmount(leftOrder);
                }
            }



            if (rightOrderTakerAssetFilledAmount >= rightOrder.takerAssetAmount) {

                batchMatchedFillResults.right[rightIdx++] = rightFillResults;

                rightFillResults = LibFillResults.FillResults(0, 0, 0, 0, 0);



                if (rightIdx == rightOrders.length) {

                    batchMatchedFillResults.left[leftIdx] = leftFillResults;
                    break;
                } else {
                    rightOrder = rightOrders[rightIdx];
                    (, rightOrderTakerAssetFilledAmount) = _getOrderHashAndFilledAmount(rightOrder);
                }
            }
        }


        return batchMatchedFillResults;
    }













    function _matchOrders(
        LibOrder.Order memory leftOrder,
        LibOrder.Order memory rightOrder,
        bytes memory leftSignature,
        bytes memory rightSignature,
        bool shouldMaximallyFillOrders
    )
        internal
        returns (LibFillResults.MatchedFillResults memory matchedFillResults)
    {



        rightOrder.makerAssetData = leftOrder.takerAssetData;
        rightOrder.takerAssetData = leftOrder.makerAssetData;


        LibOrder.OrderInfo memory leftOrderInfo = getOrderInfo(leftOrder);
        LibOrder.OrderInfo memory rightOrderInfo = getOrderInfo(rightOrder);


        address takerAddress = _getCurrentContextAddress();


        _assertFillableOrder(
            leftOrder,
            leftOrderInfo,
            takerAddress,
            leftSignature
        );
        _assertFillableOrder(
            rightOrder,
            rightOrderInfo,
            takerAddress,
            rightSignature
        );
        _assertValidMatch(
            leftOrder,
            rightOrder,
            leftOrderInfo.orderHash,
            rightOrderInfo.orderHash
        );


        matchedFillResults = LibFillResults.calculateMatchedFillResults(
            leftOrder,
            rightOrder,
            leftOrderInfo.orderTakerAssetFilledAmount,
            rightOrderInfo.orderTakerAssetFilledAmount,
            protocolFeeMultiplier,
            tx.gasprice,
            shouldMaximallyFillOrders
        );


        _updateFilledState(
            leftOrder,
            takerAddress,
            leftOrderInfo.orderHash,
            leftOrderInfo.orderTakerAssetFilledAmount,
            matchedFillResults.left
        );
        _updateFilledState(
            rightOrder,
            takerAddress,
            rightOrderInfo.orderHash,
            rightOrderInfo.orderTakerAssetFilledAmount,
            matchedFillResults.right
        );


        _settleMatchedOrders(
            leftOrderInfo.orderHash,
            rightOrderInfo.orderHash,
            leftOrder,
            rightOrder,
            takerAddress,
            matchedFillResults
        );

        return matchedFillResults;
    }










    function _settleMatchedOrders(
        bytes32 leftOrderHash,
        bytes32 rightOrderHash,
        LibOrder.Order memory leftOrder,
        LibOrder.Order memory rightOrder,
        address takerAddress,
        LibFillResults.MatchedFillResults memory matchedFillResults
    )
        internal
    {
        address leftMakerAddress = leftOrder.makerAddress;
        address rightMakerAddress = rightOrder.makerAddress;
        address leftFeeRecipientAddress = leftOrder.feeRecipientAddress;
        address rightFeeRecipientAddress = rightOrder.feeRecipientAddress;


        _dispatchTransferFrom(
            rightOrderHash,
            rightOrder.makerAssetData,
            rightMakerAddress,
            leftMakerAddress,
            matchedFillResults.left.takerAssetFilledAmount
        );


        _dispatchTransferFrom(
            leftOrderHash,
            leftOrder.makerAssetData,
            leftMakerAddress,
            rightMakerAddress,
            matchedFillResults.right.takerAssetFilledAmount
        );


        _dispatchTransferFrom(
            rightOrderHash,
            rightOrder.makerFeeAssetData,
            rightMakerAddress,
            rightFeeRecipientAddress,
            matchedFillResults.right.makerFeePaid
        );


        _dispatchTransferFrom(
            leftOrderHash,
            leftOrder.makerFeeAssetData,
            leftMakerAddress,
            leftFeeRecipientAddress,
            matchedFillResults.left.makerFeePaid
        );


        _dispatchTransferFrom(
            leftOrderHash,
            leftOrder.makerAssetData,
            leftMakerAddress,
            takerAddress,
            matchedFillResults.profitInLeftMakerAsset
        );
        _dispatchTransferFrom(
            rightOrderHash,
            rightOrder.makerAssetData,
            rightMakerAddress,
            takerAddress,
            matchedFillResults.profitInRightMakerAsset
        );


        bool didPayProtocolFees = _payTwoProtocolFees(
            leftOrderHash,
            rightOrderHash,
            matchedFillResults.left.protocolFeePaid,
            leftMakerAddress,
            rightMakerAddress,
            takerAddress
        );


        if (!didPayProtocolFees) {
            matchedFillResults.left.protocolFeePaid = 0;
            matchedFillResults.right.protocolFeePaid = 0;
        }


        if (
            leftFeeRecipientAddress == rightFeeRecipientAddress &&
            leftOrder.takerFeeAssetData.equals(rightOrder.takerFeeAssetData)
        ) {


            _dispatchTransferFrom(
                leftOrderHash,
                leftOrder.takerFeeAssetData,
                takerAddress,
                leftFeeRecipientAddress,
                matchedFillResults.left.takerFeePaid.safeAdd(matchedFillResults.right.takerFeePaid)
            );
        } else {

            _dispatchTransferFrom(
                rightOrderHash,
                rightOrder.takerFeeAssetData,
                takerAddress,
                rightFeeRecipientAddress,
                matchedFillResults.right.takerFeePaid
            );


            _dispatchTransferFrom(
                leftOrderHash,
                leftOrder.takerFeeAssetData,
                takerAddress,
                leftFeeRecipientAddress,
                matchedFillResults.left.takerFeePaid
            );
        }
    }
}

pragma solidity 0.6.11;

import "./Interfaces/ILUSDToken.sol";
import "./Dependencies/SafeMath.sol";
import "./Dependencies/console.sol";


contract LUSDToken is ILUSDToken {
    using SafeMath for uint256;

    uint256 private _totalSupply;
    string constant internal _NAME = "LUSD Stablecoin";
    string constant internal _SYMBOL = "LUSD";
    string constant internal _VERSION = "1";
    uint8 constant internal _DECIMALS = 18;



    bytes32 constant internal _PERMIT_TYPEHASH = 0x6e71edae12b1b97f4d1f60370fef10105fa2faae0126114a169c64845d6126c9;
    mapping (address => uint256) private _nonces;


    mapping (address => uint256) private _balances;
     mapping (address => mapping (address => uint256)) private _allowances;  


    address public immutable troveManagerAddress;
    address public immutable stabilityPoolAddress;
    address public immutable borrowerOperationsAddress;

    constructor
    ( 
        address _troveManagerAddress,
        address _stabilityPoolAddress,
        address _borrowerOperationsAddress
    ) 
        public 
    {  
        troveManagerAddress = _troveManagerAddress;
        emit TroveManagerAddressChanged(_troveManagerAddress);

        stabilityPoolAddress = _stabilityPoolAddress;
        emit StabilityPoolAddressChanged(_stabilityPoolAddress);

        borrowerOperationsAddress = _borrowerOperationsAddress;        
        emit BorrowerOperationsAddressChanged(_borrowerOperationsAddress);
    }



    function mint(address _account, uint256 _amount) external override {
        _requireCallerIsBorrowerOperations();
        _mint(_account, _amount);
    }

    function burn(address _account, uint256 _amount) external override {
        _requireCallerIsBOorTroveMorSP();
        _burn(_account, _amount);
    }

    function sendToPool(address _sender,  address _poolAddress, uint256 _amount) external override {
        _requireCallerIsStabilityPool();
        _transfer(_sender, _poolAddress, _amount);
    }

    function returnFromPool(address _poolAddress, address _receiver, uint256 _amount) external override {
        _requireCallerIsTroveMorSP();
        _transfer(_poolAddress, _receiver, _amount);
    }



    function totalSupply() external view override returns (uint256) {
        return _totalSupply;
    }

    function balanceOf(address account) external view override returns (uint256) {
        return _balances[account];
    }

    function transfer(address recipient, uint256 amount) external override returns (bool) {
        _requireValidRecipient(recipient);
        _transfer(msg.sender, recipient, amount);
        return true;
    }

    function allowance(address owner, address spender) external view override returns (uint256) {
        return _allowances[owner][spender];
    }

    function approve(address spender, uint256 amount) external override returns (bool) {
        _approve(msg.sender, spender, amount);
        return true;
    }

    function transferFrom(address sender, address recipient, uint256 amount) external override returns (bool) {
        _requireValidRecipient(recipient);
        _transfer(sender, recipient, amount);
        _approve(sender, msg.sender, _allowances[sender][msg.sender].sub(amount, "ERC20: transfer amount exceeds allowance"));
        return true;
    }

    function increaseAllowance(address spender, uint256 addedValue) external override returns (bool) {
        _approve(msg.sender, spender, _allowances[msg.sender][spender].add(addedValue));
        return true;
    }

    function decreaseAllowance(address spender, uint256 subtractedValue) external override returns (bool) {
        _approve(msg.sender, spender, _allowances[msg.sender][spender].sub(subtractedValue, "ERC20: decreased allowance below zero"));
        return true;
    }



    function domainSeparator() public view override returns (bytes32) {    
        return keccak256(abi.encode( 
               keccak256('EIP712Domain(string name,string version,uint256 chainId,address verifyingContract)'),
               keccak256(bytes(_NAME)), 
               keccak256(bytes(_VERSION)), 
               _chainID(),address(this)));
    }

    function permit
    (
        address owner, 
        address spender, 
        uint amount, 
        uint deadline, 
        uint8 v, 
        bytes32 r, 
        bytes32 s
    ) 
        external 
        override 
    {            
        require(deadline == 0 || deadline >= now, 'LUSD: Signature has expired');
        bytes32 digest = keccak256(abi.encodePacked(uint16(0x1901), 
                         domainSeparator(), keccak256(abi.encode(
                         _PERMIT_TYPEHASH, owner, spender, amount, 
                         _nonces[owner]++, deadline))));
        address recoveredAddress = ecrecover(digest, v, r, s);
        require(recoveredAddress != address(0) && 
                recoveredAddress == owner, 'LUSD: Recovered address from the sig is not the owner');
        _approve(owner, spender, amount);
    }

    function nonces(address owner) external view override returns (uint256) { 
        return _nonces[owner];
    }

    function _chainID() private pure returns (uint256 chainID) {
        assembly {
            chainID := chainid()
        }
    }



    function _transfer(address sender, address recipient, uint256 amount) internal {
        require(sender != address(0), "ERC20: transfer from the zero address");
        require(recipient != address(0), "ERC20: transfer to the zero address");

        _balances[sender] = _balances[sender].sub(amount, "ERC20: transfer amount exceeds balance");
        _balances[recipient] = _balances[recipient].add(amount);
        emit Transfer(sender, recipient, amount);
    }

    function _mint(address account, uint256 amount) internal {
        require(account != address(0), "ERC20: mint to the zero address");

        _totalSupply = _totalSupply.add(amount);
        _balances[account] = _balances[account].add(amount);
        emit Transfer(address(0), account, amount);
    }

    function _burn(address account, uint256 amount) internal {
        require(account != address(0), "ERC20: burn from the zero address");

        _balances[account] = _balances[account].sub(amount, "ERC20: burn amount exceeds balance");
        _totalSupply = _totalSupply.sub(amount);
        emit Transfer(account, address(0), amount);
    }

    function _approve(address owner, address spender, uint256 amount) internal {
        require(owner != address(0), "ERC20: approve from the zero address");
        require(spender != address(0), "ERC20: approve to the zero address");

        _allowances[owner][spender] = amount;
        emit Approval(owner, spender, amount);
    }



    function _requireValidRecipient(address _recipient) internal view {
        require(
            _recipient != address(0) && 
            _recipient != address(this),
            "LUSD: Cannot transfer tokens directly to the LUSD token contract or the zero address"
        );
        require(
            _recipient != stabilityPoolAddress && 
            _recipient != troveManagerAddress && 
            _recipient != borrowerOperationsAddress, 
            "LUSD: Cannot transfer tokens directly to the StabilityPool, TroveManager or BorrowerOps"
        );
    }

    function _requireCallerIsBorrowerOperations() internal view {
        require(msg.sender == borrowerOperationsAddress, "LUSDToken: Caller is not BorrowerOperations");
    }

    function _requireCallerIsBOorTroveMorSP() internal view {
        require(
            msg.sender == borrowerOperationsAddress ||
            msg.sender == troveManagerAddress ||
            msg.sender == stabilityPoolAddress,
            "LUSD: Caller is neither BorrowerOperations nor TroveManager nor StabilityPool"
        );
    }

    function _requireCallerIsStabilityPool() internal view {
        require(msg.sender == stabilityPoolAddress, "LUSD: Caller is not the StabilityPool");
    }

    function _requireCallerIsTroveMorSP() internal view {
        require(
            msg.sender == troveManagerAddress || msg.sender == stabilityPoolAddress,
            "LUSD: Caller is neither TroveManager nor StabilityPool");
    }



    function name() external view override returns (string memory) {
        return _NAME;
    }

    function symbol() external view override returns (string memory) {
        return _SYMBOL;
    }

    function decimals() external view override returns (uint8) {
        return _DECIMALS;
    }

    function version() external view override returns (string memory) {
        return _VERSION;
    }

    function permitTypeHash() external view override returns (bytes32) {
        return _PERMIT_TYPEHASH;
    }
}

pragma solidity 0.5.11;


import "./IAave.sol";
import {
    IERC20,
    InitializableAbstractStrategy
} from "../utils/InitializableAbstractStrategy.sol";

contract AaveStrategy is InitializableAbstractStrategy {
    uint16 constant referralCode = 92;


    function deposit(address _asset, uint256 _amount)
        external
        onlyVault
        returns (uint256 amountDeposited)
    {
        require(_amount > 0, "Must deposit something");

        IAaveAToken aToken = _getATokenFor(_asset);

        _getLendingPool().deposit(_asset, _amount, referralCode);
        amountDeposited = _amount;

        emit Deposit(_asset, address(aToken), amountDeposited);
    }



    function withdraw(
        address _recipient,
        address _asset,
        uint256 _amount
    ) external onlyVault returns (uint256 amountWithdrawn) {
        require(_amount > 0, "Must withdraw something");
        require(_recipient != address(0), "Must specify recipient");

        IAaveAToken aToken = _getATokenFor(_asset);

        amountWithdrawn = _amount;
        uint256 balance = aToken.balanceOf(address(this));

        aToken.redeem(_amount);
        IERC20(_asset).safeTransfer(
            _recipient,
            IERC20(_asset).balanceOf(address(this))
        );

        emit Withdrawal(_asset, address(aToken), amountWithdrawn);
    }


    function liquidate() external onlyVaultOrGovernor {
        for (uint256 i = 0; i < assetsMapped.length; i++) {

            IAaveAToken aToken = _getATokenFor(assetsMapped[i]);
            uint256 balance = aToken.balanceOf(address(this));
            if (balance > 0) {
                aToken.redeem(balance);

                IERC20 asset = IERC20(assetsMapped[i]);
                asset.safeTransfer(
                    vaultAddress,
                    asset.balanceOf(address(this))
                );
            }
        }
    }


    function checkBalance(address _asset)
        external
        view
        returns (uint256 balance)
    {

        IAaveAToken aToken = _getATokenFor(_asset);
        balance = aToken.balanceOf(address(this));
    }


    function supportsAsset(address _asset) external view returns (bool) {
        return assetToPToken[_asset] != address(0);
    }


    function safeApproveAllTokens() external onlyGovernor {
        uint256 assetCount = assetsMapped.length;
        address lendingPoolVault = _getLendingPoolCore();


        for (uint256 i = 0; i < assetCount; i++) {
            address asset = assetsMapped[i];

            IERC20(asset).safeApprove(lendingPoolVault, 0);
            IERC20(asset).safeApprove(lendingPoolVault, uint256(-1));
        }
    }


    function _abstractSetPToken(address _asset, address _aToken) internal {
        address lendingPoolVault = _getLendingPoolCore();
        IERC20(_asset).safeApprove(lendingPoolVault, 0);
        IERC20(_asset).safeApprove(lendingPoolVault, uint256(-1));
    }


    function _getATokenFor(address _asset) internal view returns (IAaveAToken) {
        address aToken = assetToPToken[_asset];
        require(aToken != address(0), "aToken does not exist");
        return IAaveAToken(aToken);
    }


    function _getLendingPool() internal view returns (IAaveLendingPool) {
        address lendingPool = ILendingPoolAddressesProvider(platformAddress)
            .getLendingPool();
        require(lendingPool != address(0), "Lending pool does not exist");
        return IAaveLendingPool(lendingPool);
    }


    function _getLendingPoolCore() internal view returns (address payable) {
        address payable lendingPoolCore = ILendingPoolAddressesProvider(
            platformAddress
        )
            .getLendingPoolCore();
        require(
            lendingPoolCore != address(uint160(address(0))),
            "Lending pool core does not exist"
        );
        return lendingPoolCore;
    }

    function _min(uint256 x, uint256 y) internal pure returns (uint256) {
        return x > y ? y : x;
    }
}
